insert into dcd (asignatura_id, codigo, descripcion, subnivel, indicador) values
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.1', 'Indagar y analizar la teoría de la abiogénesis que explica el origen de la vida, e interpretar las distintas evidencias científicas. CN', 'BGU', 'Explica el origen de la vida desde el sustento científico, análisis de evidencias y/o la realización de sencillos experimentos que fundamenten las teorías de la abiogénesis en la Tierra, la identificación de los elementos y compuestos químicos de la atmósfera de la Tierra primitiva. (Ref. I.CN.B.5.1.1.) (I.2., S.4.) I.CN.B.5.1.2 Explica la importancia de las biomoléculas a partir de la sustentación científica y/o la ejecución de experimentos sencillos sobre los procesos de abiogénesis, características básicas, estructura, diversidad y función en la materia viva. (I.3., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.11', 'Usar modelos y describir la función del ADN como portador de la información genética que controla las características de los organismos y la transmisión de la herencia, y relacionar el ADN con los cromosomas y los genes. CN', 'BGU', 'Explica desde la fundamentación científica y modelos la importancia del ADN como portador de la información genética, transmisor de la herencia, comprendiendo su estructura, función, las causas y consecuencias de la alteración genética y cromosómica. (Ref. I.CN.B.5.3.1.) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.13', 'Experimentar con los procesos de mitosis, meiosis, y demostrar la trasmisión de la información genética a la descendencia por medio de la fertilización. CN', 'BGU', 'Explica la trascendencia de la transmisión de la información genética, desde la sustentación científica y la ejecución de experimentos; la teoría cromosómica de la herencia desde la comprensión de las leyes de Mendel. (Ref. I.CN.B.5.4.1) (I.2., S.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.14', 'Describir las leyes de Mendel, diseñar patrones de cruzamiento y deducir porcentajes genotípicos y fenotípicos en diferentes generaciones. CN', 'BGU', 'Explica la trascendencia de la transmisión de la información genética, desde la sustentación científica y la ejecución de experimentos; la teoría cromosómica de la herencia desde la comprensión de las leyes de Mendel. (Ref. I.CN.B.5.4.1) (I.2., S.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.16', 'Indagar la teoría cromosómica de la herencia, y relacionarla con las leyes de Mendel. CN', 'BGU', 'Explica la trascendencia de la transmisión de la información genética, desde la sustentación científica y la ejecución de experimentos; la teoría cromosómica de la herencia desde la comprensión de las leyes de Mendel. (Ref. I.CN.B.5.4.1) (I.2., S.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.17', 'Investigar las causas de los cambios del ADN que producen alteraciones génicas, cromosómicas y genómicas, e identificar semejanzas y diferencias entre estas', 'BGU', 'Explica desde la fundamentación científica y modelos la importancia del ADN como portador de la información genética, transmisor de la herencia, comprendiendo su estructura, función, las causas y consecuencias de la alteración genética y cromosómica. (Ref. I.CN.B.5.3.1.) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.18', 'Indagar y describir los biomas del mundo e interpretarlos como sitios donde se evidencia la evolución de la biodiversidad en respuesta a los factores geográficos y climáticos', 'BGU', 'I.CN.B.5.2.1. Explica la importancia de la evolución biológica desde la sustentación científica de las teorías de la endosimbiosis, selección natural y sintética de la evolución, la relación con las diversas formas de vida con el proceso evolutivo y su repercusión para el mantenimiento de la vida en la Tierra. (I.2., I.4.) Argumenta desde la sustentación científica los tipos de diversidad biológica (a nivel de genes, especies y ecosistemas) que existen en los biomas del mundo, la importancia de estos como evidencia de la evolución de la diversidad (Ref. I.C- N.B.5.2.2) (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.19', 'Indagar en estudios científicos la biodiversidad del Ecuador, analizar los patrones de evolución de las especies nativas y endémicas representativas de los diferentes ecosistemas, y explicar su megadiversidad. CN', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.2', 'Identificar los elementos y compuestos químicos de la atmósfera de la Tierra primitiva, y relacionarlos con la formación abiogénica de las moléculas orgánicas que forman parte de la materia viva. CN', 'BGU', 'Explica el origen de la vida desde el sustento científico, análisis de evidencias y/o la realización de sencillos experimentos que fundamenten las teorías de la abiogénesis en la Tierra, la identificación de los elementos y compuestos químicos de la atmósfera de la Tierra primitiva. (Ref. I.CN.B.5.1.1.) (I.2., S.4.) I.CN.B.5.1.2 Explica la importancia de las biomoléculas a partir de la sustentación científica y/o la ejecución de experimentos sencillos sobre los procesos de abiogénesis, características básicas, estructura, diversidad y función en la materia viva. (I.3., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.20', 'Reflexionar acerca de la importancia social, económica y ambiental de la biodiversidad, e identificar la problemática y los retos del Ecuador frente al manejo sostenible de su patrimonio natural. CN', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.21', 'Indagar y examinar las diferentes actividades humanas que afectan a los sistemas globales, e inferir la pérdida de biodiversidad a escala nacional, regional y global. CN', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.22', 'Interpretar las estrategias y políticas nacionales e internacionales para la conservación de la biodiversidad insitu y ex situ, y la mitigación de problemas ambientales globales, y generar una actitud crítica, reflexiva y responsable en favor del ambiente. CN', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.23', 'Evaluar el estado de los ecosistemas marinos y costeros de Ecuador, analizando la Convención de las Naciones Unidas sobre el Derecho del Mar (CONVE- MAR) y las estrategias globales o regionales para la conservación y el uso sostenible de los recursos marítimos. CN', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.24', 'Analizar críticamente los marcos legales internacionales y compararlos con los de Ecuador, analizando su efectividad en la protección de los ecosistemas identificando iniciativas globales o regionales con un impacto positivo en el reconocimiento, promoción y la defensa de los derechos de la naturaleza', 'BGU', 'I.CN.B.5.5.1. Explica el valor de la biodiversidad, desde la fundamentación científica de los patrones de evolución de las especies nativas y endémicas. Reconoce la importancia social, económica y ambiental y la identificación de los efectos de las actividades humanas sobre la biodiversidad a nivel nacional, regional y global. (J.1., J.3.) I.CN.B.5.5.2. Argumenta y analiza con actitud crítica y reflexiva los modelos de desarrollo económico, los avances tecnológicos que cubren las necesidades del crecimiento de la población humana, las estrategias y políticas nacionales e internacionales enfocadas al desarrollo sostenible. (J.1., J.2)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.25', 'Debatir sobre los beneficios del uso del transporte público y compartido, considerando los impactos ambientales enfocados en el desarrollo sostenible. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.26', 'Proponer soluciones innovadoras a los desafíos socioambientales en la Amazonía ecuatoriana, integrando la conservación de la biodiversidad con el desarrollo social y económico de las comunidades locales promoviendo el respeto por la diversidad cultural y el compromiso con un desarrollo sostenible e inclusivo. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.4', 'Describir y comparar las características básicas de las biomoléculas a partir de sus procesos de síntesis y diversidad de polímeros. CN', 'BGU', 'Explica el origen de la vida desde el sustento científico, análisis de evidencias y/o la realización de sencillos experimentos que fundamenten las teorías de la abiogénesis en la Tierra, la identificación de los elementos y compuestos químicos de la atmósfera de la Tierra primitiva. (Ref. I.CN.B.5.1.1.) (I.2., S.4.) I.CN.B.5.1.2 Explica la importancia de las biomoléculas a partir de la sustentación científica y/o la ejecución de experimentos sencillos sobre los procesos de abiogénesis, características básicas, estructura, diversidad y función en la materia viva. (I.3., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.5', 'Usar modelos y describir la estructura, diversidad y función de las biomoléculas que constituyen la materia viva, y experimentar con procedimientos sencillos', 'BGU', 'Explica el origen de la vida desde el sustento científico, análisis de evidencias y/o la realización de sencillos experimentos que fundamenten las teorías de la abiogénesis en la Tierra, la identificación de los elementos y compuestos químicos de la atmósfera de la Tierra primitiva. (Ref. I.CN.B.5.1.1.) (I.2., S.4.) I.CN.B.5.1.2 Explica la importancia de las biomoléculas a partir de la sustentación científica y/o la ejecución de experimentos sencillos sobre los procesos de abiogénesis, características básicas, estructura, diversidad y función en la materia viva. (I.3., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.6', 'Establecer las principales evidencias de las teorías científicas sobre la evolución biológica y analizar sobre el rol de la evolución con el proceso responsable del cambio y diversificación de la vida en la Tierra. CN', 'BGU', 'I.CN.B.5.2.1. Explica la importancia de la evolución biológica desde la sustentación científica de las teorías de la endosimbiosis, selección natural y sintética de la evolución, la relación con las diversas formas de vida con el proceso evolutivo y su repercusión para el mantenimiento de la vida en la Tierra. (I.2., I.4.) Argumenta desde la sustentación científica los tipos de diversidad biológica (a nivel de genes, especies y ecosistemas) que existen en los biomas del mundo, la importancia de estos como evidencia de la evolución de la diversidad (Ref. I.C- N.B.5.2.2) (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.7', 'Analizar los procesos de variación, aislamiento y migración, relacionados con la selección natural, y explicar el proceso evolutivo. CN', 'BGU', 'I.CN.B.5.2.1. Explica la importancia de la evolución biológica desde la sustentación científica de las teorías de la endosimbiosis, selección natural y sintética de la evolución, la relación con las diversas formas de vida con el proceso evolutivo y su repercusión para el mantenimiento de la vida en la Tierra. (I.2., I.4.) Argumenta desde la sustentación científica los tipos de diversidad biológica (a nivel de genes, especies y ecosistemas) que existen en los biomas del mundo, la importancia de estos como evidencia de la evolución de la diversidad (Ref. I.C- N.B.5.2.2) (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.1.9', 'Analizar los tipos de diversidad biológica a nivel de genes, especies y ecosistemas, y plantear su importancia para el mantenimiento de la vida en el planeta. CN', 'BGU', 'I.CN.B.5.2.1. Explica la importancia de la evolución biológica desde la sustentación científica de las teorías de la endosimbiosis, selección natural y sintética de la evolución, la relación con las diversas formas de vida con el proceso evolutivo y su repercusión para el mantenimiento de la vida en la Tierra. (I.2., I.4.) Argumenta desde la sustentación científica los tipos de diversidad biológica (a nivel de genes, especies y ecosistemas) que existen en los biomas del mundo, la importancia de estos como evidencia de la evolución de la diversidad (Ref. I.C- N.B.5.2.2) (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.1', 'Analizar las hipótesis sobre la evolución de las células procariotas y eucariotas basadas en la teoría de la endosimbiosis, y establecer semejanzas y diferencias entre ambos tipos de células. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.2', 'Describir los tipos de organización en las células animales y vegetales, compara experimentalmente sus diferencias, y establecer semejanzas y diferencias entre organelos. CN', 'BGU', 'Explica desde la experimentación los tipos de organización de las células eucariotas (animales y vegetales), la estructura y función de sus organelos. (Ref. I.CN.B.5.6.1.) (I.2., I.4.) Relaciona los procesos anabólicos y catabólicos con la acción enzimática, los factores que inciden en la velocidad de las reacciones (Ref. I.CN.B.5.6.2) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.3', 'Usar modelos y describir la estructura y función de los organelos de las células eucariotas y diferenciar sus funciones en procesos anabólicos y catabólicos', 'BGU', 'Explica desde la experimentación los tipos de organización de las células eucariotas (animales y vegetales), la estructura y función de sus organelos. (Ref. I.CN.B.5.6.1.) (I.2., I.4.) Relaciona los procesos anabólicos y catabólicos con la acción enzimática, los factores que inciden en la velocidad de las reacciones (Ref. I.CN.B.5.6.2) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.2.5', 'Analizar la acción enzimática en los procesos metabólicos a nivel celular y evidenciar experimentalmente la influencia de diversos factores en la velocidad de las reacciones. CN', 'BGU', 'I.CN.B.5.6.3 Cuestiona desde la fundamentación científica, social y ética los efectos del proceso de proliferación celular alterada y la influencia de la ingeniería genética en el área de alimentación y salud de los seres humanos. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.1', 'Observar la forma y función de células y tejidos en organismos multicelulares animales y vegetales, e identificar su organización en órganos, aparatos y sistemas. CN', 'BGU', 'I.CN.B.5.7.1. Explica que en los organismos multicelulares la forma y función de las células y los tejidos determinan la organización de órganos, aparatos y sistemas (circulatorio, respiratorio, digestivo, excretor, nervioso, reproductivo, endócrino, inmunitario y estearato muscular), establece sus elementos constitutivos (células, tejidos, componentes), estructura, función en el ser humano y propone medidas para su cuidado. (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.4', 'Describir los sistemas nervioso y endocrino en animales con diferente grado de complejidad, explicar su coordinación funcional para adaptarse y responder a estímulos del ambiente, y utilizar modelos científicos que demuestren la evolución de estos sistemas. CN', 'BGU', 'I.CN.B.5.7.1. Explica que en los organismos multicelulares la forma y función de las células y los tejidos determinan la organización de órganos, aparatos y sistemas (circulatorio, respiratorio, digestivo, excretor, nervioso, reproductivo, endócrino, inmunitario y estearato muscular), establece sus elementos constitutivos (células, tejidos, componentes), estructura, función en el ser humano y propone medidas para su cuidado. (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.6', 'Observar y analizar los procesos de reproducción de animales, elaborar modelos del desarrollo embrionario, e identificar el origen de las células y la diferenciación de las estructuras. CN', 'BGU', 'I.CN.B.5.7.1. Explica que en los organismos multicelulares la forma y función de las células y los tejidos determinan la organización de órganos, aparatos y sistemas (circulatorio, respiratorio, digestivo, excretor, nervioso, reproductivo, endócrino, inmunitario y estearato muscular), establece sus elementos constitutivos (células, tejidos, componentes), estructura, función en el ser humano y propone medidas para su cuidado. (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.7', 'Examinar la estructura y función de los sistemas de transporte en las plantas, y describir la provisión de nutrientes y la excreción de desechos. CN', 'BGU', 'Explica los procesos que se realizan en las plantas (transporte, provisión de nutrientes, excreción de desechos, reproducción) desde la experimentación la identificación de sus estructuras, función y factores que determinan la actividad. (Ref. I.CN.B.5.9.1.) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.3.9', 'Observar y analizar los procesos de reproducción de las plantas, elaborar modelos del desarrollo embrionario, e identificar el origen de las células y la diferenciación de las estructuras', 'BGU', 'Explica los procesos que se realizan en las plantas (transporte, provisión de nutrientes, excreción de desechos, reproducción) desde la experimentación la identificación de sus estructuras, función y factores que determinan la actividad. (Ref. I.CN.B.5.9.1.) (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.1', 'Analizar el funcionamiento de los sistemas digestivo y excretor en el ser humano y explicar la relación funcional entre estos sistemas con flujogramas', 'BGU', 'I.CN.B.5.7.1. Explica que en los organismos multicelulares la forma y función de las células y los tejidos determinan la organización de órganos, aparatos y sistemas (circulatorio, respiratorio, digestivo, excretor, nervioso, reproductivo, endócrino, inmunitario y estearato muscular), establece sus elementos constitutivos (células, tejidos, componentes), estructura, función en el ser humano y propone medidas para su cuidado. (I.2., J.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.10', 'Analizar las causas y consecuencias de las enfermedades que afectan al sistema neuroendocrino, y proponer medidas preventivas. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.11', 'Interpretar la respuesta del cuerpo humano frente a microorganismos patógenos, describir el proceso de respuesta inmunitaria e identificar las anomalías de este sistema', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.12', 'Analizar la fecundación humana, concepción, el desarrollo embrionario y fetal, parto y aborto, y explicar de forma integral la función de la reproducción humana. CN', 'BGU', 'I.CN.B.5.10.1. Argumenta los riesgos de una maternidad/paternidad prematura, según su proyecto de vida, partiendo del análisis crítico y reflexivo de la salud sexual y reproductiva (fecundación/concepción, desarrollo embrionario y fetal, parto, aborto, formas de promoción, prevención y protección) y sus implicaciones. (S.1., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.13', 'Indagar acerca del crecimiento y desarrollo del ser humano, reflexionar sobre la sexualidad, la promoción, prevención y protección de la salud sexual, reproductiva y afectiva. CN', 'BGU', 'I.CN.B.5.10.1. Argumenta los riesgos de una maternidad/paternidad prematura, según su proyecto de vida, partiendo del análisis crítico y reflexivo de la salud sexual y reproductiva (fecundación/concepción, desarrollo embrionario y fetal, parto, aborto, formas de promoción, prevención y protección) y sus implicaciones. (S.1., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.14', 'Relacionar la salud sexual y reproductiva con las implicaciones en el proyecto de vida', 'BGU', 'I.CN.B.5.10.1. Argumenta los riesgos de una maternidad/paternidad prematura, según su proyecto de vida, partiendo del análisis crítico y reflexivo de la salud sexual y reproductiva (fecundación/concepción, desarrollo embrionario y fetal, parto, aborto, formas de promoción, prevención y protección) y sus implicaciones. (S.1., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.2', 'Diseñar investigaciones experimentales y reconocer el valor nutricional de diferentes alimentos de uso cotidiano según la composición de sus biomoléculas, y establecer sus efectos en el metabolismo y la salud humana. CN', 'BGU', 'I.CN.B.5.8.1. Elabora un plan de salud integral, a partir de la comprensión de las enfermedades, desórdenes alimenticios y efectos del consumo de alcohol y las drogas que afectan al sistema nervioso y endocrino, así como de los problemas generados por la falta de ejercicio, la exposición a la contaminación ambiental y el consumo de alimentos contaminados, reconociendo el valor nutricional de los alimentos de uso cotidiano. (I.1., I.4.) I.CN.B.5.8.2. Expone, desde la investigación de campo, la importancia de los programas de salud pública, la accesibilidad a la salud individual y colectiva, el desarrollo y aplicación de la Biotecnología al campo de la Medicina y la Agricultura. (S.1., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.3', 'Analizar y aplicar buenas prácticas que contribuyen a mantener un cuerpo saludable, y elaborar un plan de salud que considere una alimentación balanceada de acuerdo a su edad y actividad para asegurar su salud integral. CN', 'BGU', 'I.CN.B.5.8.1. Elabora un plan de salud integral, a partir de la comprensión de las enfermedades, desórdenes alimenticios y efectos del consumo de alcohol y las drogas que afectan al sistema nervioso y endocrino, así como de los problemas generados por la falta de ejercicio, la exposición a la contaminación ambiental y el consumo de alimentos contaminados, reconociendo el valor nutricional de los alimentos de uso cotidiano. (I.1., I.4.) I.CN.B.5.8.2. Expone, desde la investigación de campo, la importancia de los programas de salud pública, la accesibilidad a la salud individual y colectiva, el desarrollo y aplicación de la Biotecnología al campo de la Medicina y la Agricultura. (S.1., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.4', 'Indagar acerca de las enfermedades nutricionales y desórdenes alimenticios más comunes que afectan a la población ecuatoriana, diseñar y ejecutar una investigación en relación a estas, su vínculo con la dimensión psicológica y comunicar por diferentes medios las medidas preventivas en cuanto a salud y nutrición', 'BGU', 'I.CN.B.5.8.1. Elabora un plan de salud integral, a partir de la comprensión de las enfermedades, desórdenes alimenticios y efectos del consumo de alcohol y las drogas que afectan al sistema nervioso y endocrino, así como de los problemas generados por la falta de ejercicio, la exposición a la contaminación ambiental y el consumo de alimentos contaminados, reconociendo el valor nutricional de los alimentos de uso cotidiano. (I.1., I.4.) I.CN.B.5.8.2. Expone, desde la investigación de campo, la importancia de los programas de salud pública, la accesibilidad a la salud individual y colectiva, el desarrollo y aplicación de la Biotecnología al campo de la Medicina y la Agricultura. (S.1., I.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.5', 'Usar modelos y describir los sistemas circulatorio y respiratorio en el ser humano, y establecer la relación funcional entre ellos, la cual mantiene el equilibrio homeostático. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.6', 'Indagar en diversas fuentes y sintetizar información sobre las enfermedades causadas por el consumo de tabaco, la falta de ejercicio, la exposición a contaminantes ambientales y a alimentos contaminados, y proponer medidas preventivas y la práctica de buenos hábitos. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.7', 'Usar modelos y describir el sistema osteoartromuscular del ser humano, en cuanto a su estructura y función, y proponer medidas para su cuidado. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.8', 'Establecer la relación entre la estructura y función el sistema nervioso y del sistema endocrino, en cuanto a su fisiología y la respuesta a la acción hormonal. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.4.9', 'Indagar en diversas fuentes sobre los efectos nocivos en el sistema nervioso ocasionados por el consumo de alcohol y otras drogas, y proponer medidas preventivas. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.10', 'Interpretar modelos poblacionales que relacionan el crecimiento poblacional con diferentes modelos de desarrollo económico, y tomar una postura frente al enfoque del uso sustentable de los recursos naturales. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.11', 'Planificar y ejecutar una investigación sobre los diferentes avances tecnológicos que cubren las necesidades de la creciente población humana, con un enfoque de desarrollo sostenible. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.12', 'Evaluar planes de salud integral justificando la importancia de la salud mental de niños, niñas, adolescentes, personas jóvenes, adultas y adultas mayores', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.13', 'Evaluar las consecuencias sociales y ambientales de la aplicación de biotecnologías como la ingeniería genética y propone con otras personas de su edad soluciones a problemas locales', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.2', 'Indagar sobre la evolución de los pinzones de Galápagos que sustentó la teoría de la selección natural de Darwin, y analizar que se complementa con la teoría sintética de la evolución, propuesta por científicos contemporáneos', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.4', 'Indagar sobre el desarrollo de la Biotecnología en el campo de la Medicina y la Agricultura, e interpretar su aplicación en el mejoramiento de la alimentación y la nutrición de las personas. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.6', 'Indagar sobre la genética de poblaciones, analizar e inferir los resultados de binomios genéticos', 'BGU', 'Explica la trascendencia de la transmisión de la información genética, desde la sustentación científica y la ejecución de experimentos; la teoría cromosómica de la herencia desde la comprensión de las leyes de Mendel. (Ref. I.CN.B.5.4.1) (I.2., S.4.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.7', 'Buscar, registrar y sistematizar información de diversas fuentes sobre el cáncer, y relacionarlo con el proceso de proliferación celular alterada. CN', 'BGU', 'I.CN.B.5.6.3 Cuestiona desde la fundamentación científica, social y ética los efectos del proceso de proliferación celular alterada y la influencia de la ingeniería genética en el área de alimentación y salud de los seres humanos. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.8', 'Indagar las aplicaciones de la ingeniería genética en la producción de alimentos y fármacos, sus implicaciones en la vida actual, y explicar el efecto de la terapia génica en el tratamiento de enfermedades humanas, considerando los cuestionamientos éticos y sociales', 'BGU', 'I.CN.B.5.6.3 Cuestiona desde la fundamentación científica, social y ética los efectos del proceso de proliferación celular alterada y la influencia de la ingeniería genética en el área de alimentación y salud de los seres humanos. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'BIO'), 'B.5.5.9', 'Indagar sobre los programas de salud pública sustentados en políticas estatales y en investigaciones socioeconómicas, y analizar sobre la importancia de la accesibilidad a la salud individual y colectiva, especialmente para poblaciones marginales, aisladas o de escasos recursos. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.1', 'Determinar el origen y evolución histórica del concepto “ciudadanía” en la Grecia y la Roma antigua. CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.10', 'Discernir la igualdad como principio generador de opciones y oportunidades para todos. CS', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.11', 'Establecer la relación entre individuo, sociedad y poder político, a partir de los derechos universales y desde el estudio de casos (la disidencia política, los desplazados, los refugiados). CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.12', 'Analizar la evolución del concepto “igualdad natural”, a partir del acceso al sufragio universal por los diferentes grupos sociales (personas esclavizadas, mujeres, analfabetos, personas privadas de libertad, migrantes, personas con discapacidad, grupos minoritarios y/o vulnerables, etc.)', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.13', 'Analizar los derechos y deberes de las personas en situación de movilidad humana para promover el respeto a los derechos humanos, la integración social y el acceso equitativo a servicios básicos en contextos de migración, desplazamiento o refugio', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.14', 'Reconocer y defender sus derechos como ciudadano o ciudadana, demostrando un profundo conocimiento de la legislación vigente y el valor de ejercerlos como parte de su autocuidado y crecimiento personal. CS', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.15', 'Reconocer las características de condiciones laborales justas para garantizar un entorno de trabajo equitativo y respetuoso en su lugar de empleo. CS', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.2', 'Determinar el origen y evolución histórica del concepto “derechos” a partir de la organización política de la sociedad (polis). CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.3', 'Analizar los procesos históricos que propiciaron la Declaración de los Derechos del Hombre y del Ciudadano, mediante el análisis multicausal de los mismos. CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.4', 'Discutir los procesos históricos que propiciaron la Declaración de los Derechos de la Mujer y la Ciudadana, mediante el análisis multicausal de los mismos. CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.5', 'Determinar la trascendencia de la Declaración Universal de los Derechos Humanos, desde la comprensión de su significado político. CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.6', 'Reconocer la igualdad natural de los seres humanos y la protección de la vida frente a la arbitrariedad del poder desde el análisis político. CS', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.7', 'Identificar y analizar cada una de las diferentes generaciones de derechos y el contexto histórico de su surgimiento. CS', 'BGU', 'CS.EC.5.1.1. Analiza el origen y evolución histórica de “ciudadanía” y “derechos” y los efectos que trae consigo la concepción de estos términos en la relación entre individuo y sociedad. (J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.1.9', 'Explicar el principio de igualdad, a través del ejercicio del sufragio universal como condición de participación igualitaria. CS', 'BGU', 'I.CS.EC.5.2.1. Examina la igualdad natural de los seres humanos, su traducción jurídica como base para la protección frente a la arbitrariedad del poder y su expresión en todos los ámbitos. (J.1., J.2., J.3., S.1.) I.CS.EC.5.2.2. Argumenta que la igualdad natural de los seres humanos está dirigida a todos los grupos sociales, como generador de igualdad de opciones y oportunidades, considerando al sufragio universal como condición de participación igualitaria. (J.1., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.1', 'Contextualizar el nacimiento de la democracia moderna, considerando los procesos históricos que la alumbraron. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.10', 'Analizar la definición de democracia representativa, identificando sus límites y dificultades, considerando la distancia entre gobernantes y gobernados, electores y elegidos, los riesgos de tomar decisiones en nombre del electorado y la ausencia de rendición de cuentas. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.11', 'Establecer la importancia de la rendición de cuentas y la aplicación de sistemas de control como mecanismos para reforzar y afianzar los sistemas democráticos representativos. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.12', 'Definir el principio de deliberación a partir de sus implicaciones como procedimiento colectivo de toma de decisiones. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.13', 'Examinar la posible complementariedad de la democracia representativa y la democracia deliberativa. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.14', 'Evaluar la necesidad de la deliberación como esfera política, considerando su aplicabilidad y las dificultades que conlleva la realización del ideal deliberativo. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.15', 'Establecer las ventajas y las limitaciones de la democracia deliberativa, considerando aspectos como la posibilidad de expresión social, la falta de información del público, entre otros. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.16', 'Identificar los mecanismos de deliberación pública, considerando su complejidad y su aplicabilidad', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.18', 'Reconocer la democracia como una experiencia social enfocándose en el análisis de sus manifestaciones y expresiones en la vida cotidiana y en las prácticas ciudadanas comunes. CS', 'BGU', 'I.CS.EC.5.5.1. Ejemplifica la democracia como una experiencia social que puede llevarse a cabo en los diferentes espacios cotidianos mediante mecanismos de expresión y deliberación como forma de consenso y disenso. (J.1., S.1., S4) I.CS.EC.5.5.2. Argumenta la importancia del cumplimiento de las normas y señales de tránsito promoviendo una cultura de respeto y seguridad vial. (J.3., S.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.19', 'Analizar ejemplos de procesos deliberativos en el hogar, la escuela y la comunidad, poniendo énfasis en los mecanismos que los propician, facilitan y/o dificultan. CS', 'BGU', 'I.CS.EC.5.5.1. Ejemplifica la democracia como una experiencia social que puede llevarse a cabo en los diferentes espacios cotidianos mediante mecanismos de expresión y deliberación como forma de consenso y disenso. (J.1., S.1., S4) I.CS.EC.5.5.2. Argumenta la importancia del cumplimiento de las normas y señales de tránsito promoviendo una cultura de respeto y seguridad vial. (J.3., S.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.2', 'Explicar la democracia moderna mediante el análisis de su significado radical: inexistencia de títulos naturales para gobernar, como el principio de filiación, el buen nacimiento, el linaje, la riqueza, la edad o la meritocracia. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.20', 'Discutir nuevos mecanismos de expresión y prácticas deliberativas, considerando las diversas formas de relación entre los ciudadanos en los nuevos espacios (redes sociales, Internet, etc.). CS', 'BGU', 'I.CS.EC.5.5.1. Ejemplifica la democracia como una experiencia social que puede llevarse a cabo en los diferentes espacios cotidianos mediante mecanismos de expresión y deliberación como forma de consenso y disenso. (J.1., S.1., S4) I.CS.EC.5.5.2. Argumenta la importancia del cumplimiento de las normas y señales de tránsito promoviendo una cultura de respeto y seguridad vial. (J.3., S.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.21', 'Aplicar el diálogo y la deliberación como forma de consenso y disenso casos para contribuir a la formación de una cultura de paz. CS', 'BGU', 'I.CS.EC.5.5.1. Ejemplifica la democracia como una experiencia social que puede llevarse a cabo en los diferentes espacios cotidianos mediante mecanismos de expresión y deliberación como forma de consenso y disenso. (J.1., S.1., S4) I.CS.EC.5.5.2. Argumenta la importancia del cumplimiento de las normas y señales de tránsito promoviendo una cultura de respeto y seguridad vial. (J.3., S.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.22', 'Justificar la importancia del respeto a las normas y señales de tránsito, proponiendo medidas para mejorar la seguridad para peatones, personas con discapacidad, movilidad reducida y grupos vulnerables', 'BGU', 'I.CS.EC.5.5.1. Ejemplifica la democracia como una experiencia social que puede llevarse a cabo en los diferentes espacios cotidianos mediante mecanismos de expresión y deliberación como forma de consenso y disenso. (J.1., S.1., S4) I.CS.EC.5.5.2. Argumenta la importancia del cumplimiento de las normas y señales de tránsito promoviendo una cultura de respeto y seguridad vial. (J.3., S.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.3', 'Determinar los parámetros sobre los que se construye el concepto de ciudadanía en la democracia moderna, su concepción y roles, a partir del análisis de las características de esta última. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.4', 'Discutir de manera informada la implicación de los principios de alternabilidad y de la despersonalización del poder como fundamentos de un sistema democrático pluralista. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.5', 'Determinar las contradicciones del significado de soberanía del pueblo, considerando la evolución del concepto y sus cambios sustanciales. CS', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.6', 'Contrastar los derechos civiles y los derechos políticos, a partir del análisis de las características particulares de cada uno. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.7', 'Describir los procesos de búsqueda de la legitimidad del poder político, por medio del análisis de los mecanismos de legitimación social. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.2.9', 'Examinar el significado de la representación política, considerando las contribuciones de la democracia representativa. CS', 'BGU', 'I.CS.EC.5.4.1. Contrasta las características de los derechos civiles, los derechos políticos y la representación política en la democracia social y en la democracia política. (J.1.,J.3., I.1.) I.CS.EC.5.4.2. Analiza los procesos de legitimidad y representación política, partiendo del análisis de la deliberación y la implementación de mecanismos de control para el afianzamiento de los sistemas democráticos representativos. (J.1., J.2.) I.CS.EC.5.4.3. Argumenta las ventajas y limitaciones de la democracia deliberativa, democracia social y democracia política, analizando la necesidad de contar con mecanismos de deliberación pública. (I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.1', 'Explicar el desarrollo de la democracia en Ecuador desde un Estado excluyente en 1830, hasta llegar a la declaración de Estado plurinacional establecida en la Constitución del 2008. CS', 'BGU', 'I.CS.EC.5.6.1 Analiza el desarrollo de la democracia en el país identificando los procesos inclusivos, los alcances, limitaciones o dificultades en la resolución de demandas y expectativas sociales, reconociendo el derecho ciudadano de exigir la rendición de cuentas y/o la revocatoria del mandato. (J.1., J.2., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.2', 'Discutir la cultura nacional fundamentada en la plurinacionalidad, tomando en cuenta los aportes que cada componente brinda desde su especificidad. CS', 'BGU', 'I.CS.EC.5.7.1. Examina la cultura nacional fundamentada en la plurinacionalidad, valorando los aportes de cada cultura y sus luchas sociales y políticas por el cumplimiento de los derechos sociales en pos de una sociedad intercultural y la armonía social. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.3', 'Analizar y valorar cada uno de los fundamentos sociales del Ecuador (indígena, afroecuatoriano, mestizo y montubio) como un camino en la comprensión de la otredad y de la armonía social. CS', 'BGU', 'I.CS.EC.5.7.1. Examina la cultura nacional fundamentada en la plurinacionalidad, valorando los aportes de cada cultura y sus luchas sociales y políticas por el cumplimiento de los derechos sociales en pos de una sociedad intercultural y la armonía social. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.4', 'Comprender y valorar los aportes particulares de cada cultura en la construcción de una sociedad intercultural. CS', 'BGU', 'I.CS.EC.5.7.1. Examina la cultura nacional fundamentada en la plurinacionalidad, valorando los aportes de cada cultura y sus luchas sociales y políticas por el cumplimiento de los derechos sociales en pos de una sociedad intercultural y la armonía social. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.5', 'Determinar la evolución histórica de las demandas sociales de los pueblos y nacionalidades, en función de la construcción de un Estado incluyente y sostenible', 'BGU', 'I.CS.EC.5.6.1 Analiza el desarrollo de la democracia en el país identificando los procesos inclusivos, los alcances, limitaciones o dificultades en la resolución de demandas y expectativas sociales, reconociendo el derecho ciudadano de exigir la rendición de cuentas y/o la revocatoria del mandato. (J.1., J.2., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.6', 'Reconocer la democracia como forma paradójica, a partir de su dificultad para concretar las expectativas sociales (igualdad social, movilidad social, autonomía del individuo). CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.7', 'Identificar las limitaciones de la democracia, considerando la persistencia de exclusiones sociales, la tendencia a la corrupción y el surgimiento de nuevas élites', 'BGU', 'I.CS.EC.5.3.1. Ejemplifica el origen de la democracia moderna y la alternabilidad, sus contradicciones (soberanía del pueblo y democracia para todos) y sus limitaciones (corrupción, persistencia de la exclusión social y surgimiento de nuevas élites) y la concepción natural y hereditaria del poder, destacando el significado y rol de la ciudadanía. (J.1., J.3.) I.CS.EC.5.3.2. Examina la definición, límites y dificultades de la democracia representativa y deliberativa reconociendo la posible complementariedad entre ellas y el rol de la ciudadanía. (J.1., J.2., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.8', 'Explicar el carácter ambiguo y complejo de la política, a partir del análisis de las luchas sociales y las luchas políticas por el cumplimiento de los derechos sociales', 'BGU', 'I.CS.EC.5.7.1. Examina la cultura nacional fundamentada en la plurinacionalidad, valorando los aportes de cada cultura y sus luchas sociales y políticas por el cumplimiento de los derechos sociales en pos de una sociedad intercultural y la armonía social. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.3.9', 'Describir los alcances y limitaciones de la representación política otorgada a los representantes de la ciudadanía, reconociendo el derecho ciudadano de exigir la rendición de cuentas y/o la revocatoria del mandato', 'BGU', null),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.10', 'Identificar formas de republicanismo (federalismo, centralismo y confederalismo), a partir del análisis de determinados estados latinoamericanos', 'BGU', 'I.CS.EC.5.10.1. Examina las formas y postulados del republicanismo en contraste con otras formas de comprender la democracia, partiendo del análisis de casos. (J.1., I.4.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.12', 'Explicar los roles que cumplen las funciones del Estado ecuatoriano a partir del análisis de los mecanismos de ordenamiento social, estructura y esquema de funcionamiento. CS', 'BGU', 'I.CS.EC.5.8.2. Explica cómo los ingresos gubernamentales financian bienes y servicios públicos, la importancia de pagar impuestos, y describe servicios protegidos por leyes de protección al consumidor. (J.1., J.3.) I.CS.EC.5.8.3. Analiza los factores de la gestión gubernamental que influyen en la desigualdad económica y social, evaluando su impacto en la población. (J.1., J.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.13', 'Explicar cómo los ingresos de los gobiernos se utilizan para proveer bienes y servicios públicos, por qué es necesario pagar impuestos, y cómo ciertos servicios están protegidos por leyes o regulaciones de protección al consumidor. CS', 'BGU', 'I.CS.EC.5.8.2. Explica cómo los ingresos gubernamentales financian bienes y servicios públicos, la importancia de pagar impuestos, y describe servicios protegidos por leyes de protección al consumidor. (J.1., J.3.) I.CS.EC.5.8.3. Analiza los factores de la gestión gubernamental que influyen en la desigualdad económica y social, evaluando su impacto en la población. (J.1., J.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.14', 'Evaluar la influencia de la gestión gubernamental en la desigualdad económica y social', 'BGU', 'I.CS.EC.5.8.2. Explica cómo los ingresos gubernamentales financian bienes y servicios públicos, la importancia de pagar impuestos, y describe servicios protegidos por leyes de protección al consumidor. (J.1., J.3.) I.CS.EC.5.8.3. Analiza los factores de la gestión gubernamental que influyen en la desigualdad económica y social, evaluando su impacto en la población. (J.1., J.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.2', 'Identificar y analizar el rol de cada uno de los componentes del Estado: fuerzas armadas, derecho (leyes), tribunales de justicia, burocracia, cárceles, aparatos ideológicos (medios de comunicación), etc., y su impacto en las distintas clases sociales. CS', 'BGU', 'I.CS.EC.5.8.2. Explica cómo los ingresos gubernamentales financian bienes y servicios públicos, la importancia de pagar impuestos, y describe servicios protegidos por leyes de protección al consumidor. (J.1., J.3.) I.CS.EC.5.8.3. Analiza los factores de la gestión gubernamental que influyen en la desigualdad económica y social, evaluando su impacto en la población. (J.1., J.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.3', 'Diferenciar Estado, nación y gobierno a través de la identificación de sus funciones específicas y su rol histórico. CS', 'BGU', 'I.CS.EC.5.8.2. Explica cómo los ingresos gubernamentales financian bienes y servicios públicos, la importancia de pagar impuestos, y describe servicios protegidos por leyes de protección al consumidor. (J.1., J.3.) I.CS.EC.5.8.3. Analiza los factores de la gestión gubernamental que influyen en la desigualdad económica y social, evaluando su impacto en la población. (J.1., J.2.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.4', 'Determinar el significado de las Asambleas Nacionales Constituyentes desde las revoluciones del siglo XVIII. CS', 'BGU', 'I.CS.EC.5.9.1. Examina la evolución y la necesidad de las Asambleas Constituyentes, reconociendo al pueblo como sujeto de ellas y a sus instrumentos jurídicos como expresión política de la sociedad. (J.1., J.3.) I.CS.EC.5.9.2. Reconoce la progresión de los derechos de ciudadanía mediante el análisis de las cartas constitucionales y de la Constitución de la República del Ecuador de 2008. (J.1., J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.6', 'Identificar al pueblo como sujeto de las Asambleas Constituyentes, a partir del análisis del principio de soberanía. CS', 'BGU', 'I.CS.EC.5.9.1. Examina la evolución y la necesidad de las Asambleas Constituyentes, reconociendo al pueblo como sujeto de ellas y a sus instrumentos jurídicos como expresión política de la sociedad. (J.1., J.3.) I.CS.EC.5.9.2. Reconoce la progresión de los derechos de ciudadanía mediante el análisis de las cartas constitucionales y de la Constitución de la República del Ecuador de 2008. (J.1., J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.7', 'Comparar las cartas constitucionales del Ecuador atendiendo a la progresión de los derechos de ciudadanía', 'BGU', 'I.CS.EC.5.9.1. Examina la evolución y la necesidad de las Asambleas Constituyentes, reconociendo al pueblo como sujeto de ellas y a sus instrumentos jurídicos como expresión política de la sociedad. (J.1., J.3.) I.CS.EC.5.9.2. Reconoce la progresión de los derechos de ciudadanía mediante el análisis de las cartas constitucionales y de la Constitución de la República del Ecuador de 2008. (J.1., J.3.)'),
  ((select id from asignaturas where codigo = 'CIU'), 'EC.5.4.9', 'Señalar los postulados del republicanismo, tomando en cuenta las diferencias con otros modelos de organización política. CS', 'BGU', 'I.CS.EC.5.10.1. Examina las formas y postulados del republicanismo en contraste con otras formas de comprender la democracia, partiendo del análisis de casos. (J.1., I.4.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.1', 'Realizar producciones artísticas (una canción, un dibujo, una escultura, un monólogo, una instalación, etc.) a partir de temas de interés personal o social, cuestionamientos, preocupaciones o ideas relevantes para la juventud', 'BGU', 'I.ECA.5.3.1. Organiza de manera coherente un proceso de creación artística o un evento cultural, y hace un esfuerzo por mantener sus fases, realizando los ajustes necesarios cuando se presentan problemas. (J.4., S.4.) Argumenta razonadamente el proceso seguido en la elaboración de una producción artística o en la organización de un evento cultural, valora y autoevalúa su propio trabajo. (Ref.I.ECA.5.3.2.) (I.1., J.3) Desarrolla una nueva destreza como resultado de un proceso de autoaprendizaje, utilizando fuentes seleccionadas por el estudiante. (Ref. I.ECA.5.3.3.) (I.4., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.10', 'Explorar su propia identidad, reconociendo sus fortalezas, debilidades, valores y metas a través de la automotivación al buscar oportunidades de crecimiento personal para gestionar sus emociones y tomar decisiones conscientes', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.2', 'Autoevaluarse durante los procesos de creación artística usando criterios técnicos, reconociendo las propias emociones y realizando los ajustes necesarios para lograr el producto deseado', 'BGU', 'I.ECA.5.3.1. Organiza de manera coherente un proceso de creación artística o un evento cultural, y hace un esfuerzo por mantener sus fases, realizando los ajustes necesarios cuando se presentan problemas. (J.4., S.4.) Argumenta razonadamente el proceso seguido en la elaboración de una producción artística o en la organización de un evento cultural, valora y autoevalúa su propio trabajo. (Ref.I.ECA.5.3.2.) (I.1., J.3) Desarrolla una nueva destreza como resultado de un proceso de autoaprendizaje, utilizando fuentes seleccionadas por el estudiante. (Ref. I.ECA.5.3.3.) (I.4., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.6', 'Planificar de forma razonada los procesos propios de creación o interpretación artística, considerando las necesidades de expresión y comunicación, y elaborar un guion con los pasos a seguir y los recursos necesarios', 'BGU', 'I.ECA.5.3.1. Organiza de manera coherente un proceso de creación artística o un evento cultural, y hace un esfuerzo por mantener sus fases, realizando los ajustes necesarios cuando se presentan problemas. (J.4., S.4.) Argumenta razonadamente el proceso seguido en la elaboración de una producción artística o en la organización de un evento cultural, valora y autoevalúa su propio trabajo. (Ref.I.ECA.5.3.2.) (I.1., J.3) Desarrolla una nueva destreza como resultado de un proceso de autoaprendizaje, utilizando fuentes seleccionadas por el estudiante. (Ref. I.ECA.5.3.3.) (I.4., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.1.7', 'Identificar un ámbito o forma de expresión artística de interés (cerámica, joyería, mimo, percusión corporal, video arte, etc.), utilizar recursos para el autoaprendizaje (libros, videos, aprendizaje entre pares, consulta a especialistas) y aplicar los conocimientos y habilidades adquiridos en la creación de un pequeño proyecto o producto artístico', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.1', 'Seleccionar, ensayar e interpretar obras musicales y escénicas (teatro, musicales, títeres, danza, ópera, etc.) asumiendo distintos roles (actor, director, escenógrafo, etc.) y contribuyendo a la consecución del resultado esperado', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.2', 'Representar historias reales o inventadas a través de un guion gráfico, una secuencia sonora, una representación teatral, una creación corporal o un video', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.3', 'Diseñar y desarrollar pequeños proyectos artísticos colectivos centrados en un tema de interés individual o social (discriminación, contaminación sonora, género, etc.) previendo todas las fases del proceso, desde su creación hasta su difusión y presentación', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.4', 'Ensayar y grabar en video o audio distintas versiones de una improvisación o interpretación/representación artística (musical, dramática, corporal, etc.), revisar las diferentes versiones y reflexionar en grupo sobre los aspectos positivos y mejorables de cada una de ellas', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.5', 'Documentar, con fotografías, dibujos, registros sonoros o audiovisuales, los procesos creativos y las exposiciones o representaciones colectivas realizadas, y crear catálogos, programas radiofónicos, cortos u otros productos que den cuenta de los mismos', 'BGU', 'Conoce las técnicas, recursos de los distintos lenguajes artísticos para expresar ideas, sentimientos y emociones. (Ref. I.ECA.5.3.4.) (I.2., S.3.) Asume el trabajo compartido con responsabilidad, respetando las intervenciones y aportaciones de los demás, y colaborando en la elaboración de un proyecto artístico colectivo, desde la idea inicial hasta su conclusión. (Ref. I.ECA.5.3.5.) (S.1., S.4.) Selecciona los recursos más adecuados (fotografía, presentaciones multimedia, documentos escritos, videos, etc.) para documentar los procesos de creación artística. (Ref. I.ECA.5.3.6.) (I.3., S.3.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.6', 'Participar en las distintas fases del proceso creativo (identificar un tema, investigar, explorar opciones, seleccionar y desarrollar ideas, recibir críticas, revisar y perfeccionar, interpretar o exponer), crear una obra original (de danza, música, escultura, pintura, cine, etc.), presentarla y debatir los resultados con la audiencia, con un artista invitado, un crítico u otro especialista', 'BGU', null),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.2.8', 'Indagar sobre la música de compositores y compositoras del repertorio clásico o popular, y componer una pieza o canción con un estilo similar al de los compositores elegidos; ensayarla, grabarla y publicarla en una web o un blog para que los oyentes puedan escucharla y comentarla', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.1', 'Investigar, analizar y comparar los recursos usados por artistas compositores, coreógrafos, dramaturgos, etc. para comunicar determinadas ideas, temas o conceptos (la naturaleza, eventos históricos, problemáticas sociales, optimismo, pesimismo, etc.) y para despertar emociones o sentimientos (alegría, tristeza, tensión, ira, etc.) en los oyentes o espectadores, y crear presentaciones multimedia que ilustren cómo se consigue el efecto deseado en cada forma de expresión artística', 'BGU', 'Observa producciones artísticas (artes visuales, cine, publicidad, fotografía, música, teatro, etc.) para expresar ideas y para generar emociones, y crea presentaciones, para explicar o aplicar lo aprendido durante los procesos de observación. (Ref. I.ECA.5.2.1.) (S.3., I.1.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.11', 'Investigar sobre los procesos formativos para dedicarse profesionalmente a distintos ámbitos del arte o la cultura y sobre la vida y el trabajo de algunos profesionales y elaborar videos con entrevistas breves o documentales que ilustren distintas opciones', 'BGU', 'Selecciona, y reúne muestras significativas de las producciones realizadas en un portafolio, u otro recurso digital adecuado para presentar y reflexionar sobre las creaciones artísticas propias. (Ref. I.ECA.5.4.1.) (I.4., S.3.) Utiliza diferentes recursos audiovisuales y tecnológicos en la elaboración de catálogos de profesiones relacionadas con el arte y la cultura, la producción de audiovisuales en las que algunos profesionales ofrezcan testimonios sobre su trabajo. (Ref. I.ECA.5.4.2.) (I.3., S.3.) Reconoce el papel que desempeñan las tecnologías de la información y la comunicación a la hora de crear, almacenar, distribuir y acceder a manifestaciones culturales y artísticas. (Ref. I.ECA.5.4.3.) (I.3., S.3.) I.ECA.5.4.4. Asume responsabilidades individuales dentro del proyecto grupal y cumple con los plazos establecidos con una capacidad sobresaliente para trabajar en equipo, aportando ideas creativas y valorando las contribuciones de los demás. (J.3.,S.4.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.12', 'Reconocer los materiales, las herramientas y las técnicas del grafiti y otras formas de arte urbano mediante la observación del entorno cotidiano o fotografías de estas representaciones en las ciudades, y crear una exposición virtual de imágenes relacionadas con el tema', 'BGU', 'Selecciona, y reúne muestras significativas de las producciones realizadas en un portafolio, u otro recurso digital adecuado para presentar y reflexionar sobre las creaciones artísticas propias. (Ref. I.ECA.5.4.1.) (I.4., S.3.) Utiliza diferentes recursos audiovisuales y tecnológicos en la elaboración de catálogos de profesiones relacionadas con el arte y la cultura, la producción de audiovisuales en las que algunos profesionales ofrezcan testimonios sobre su trabajo. (Ref. I.ECA.5.4.2.) (I.3., S.3.) Reconoce el papel que desempeñan las tecnologías de la información y la comunicación a la hora de crear, almacenar, distribuir y acceder a manifestaciones culturales y artísticas. (Ref. I.ECA.5.4.3.) (I.3., S.3.) I.ECA.5.4.4. Asume responsabilidades individuales dentro del proyecto grupal y cumple con los plazos establecidos con una capacidad sobresaliente para trabajar en equipo, aportando ideas creativas y valorando las contribuciones de los demás. (J.3.,S.4.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.13', 'Colaborar con sus pares para diseñar y construir una instalación artística que represente un espacio específico con materiales del medio aportando con ideas a un proyecto artístico colectivo, valorando las aportaciones de los demás en el desarrollo de un proyecto artístico asumiendo responsabilidades individuales dentro de un proyecto grupal y cumplir con los plazos establecidos', 'BGU', 'Selecciona, y reúne muestras significativas de las producciones realizadas en un portafolio, u otro recurso digital adecuado para presentar y reflexionar sobre las creaciones artísticas propias. (Ref. I.ECA.5.4.1.) (I.4., S.3.) Utiliza diferentes recursos audiovisuales y tecnológicos en la elaboración de catálogos de profesiones relacionadas con el arte y la cultura, la producción de audiovisuales en las que algunos profesionales ofrezcan testimonios sobre su trabajo. (Ref. I.ECA.5.4.2.) (I.3., S.3.) Reconoce el papel que desempeñan las tecnologías de la información y la comunicación a la hora de crear, almacenar, distribuir y acceder a manifestaciones culturales y artísticas. (Ref. I.ECA.5.4.3.) (I.3., S.3.) I.ECA.5.4.4. Asume responsabilidades individuales dentro del proyecto grupal y cumple con los plazos establecidos con una capacidad sobresaliente para trabajar en equipo, aportando ideas creativas y valorando las contribuciones de los demás. (J.3.,S.4.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.4', 'Reconocer a artistas y agentes culturales (individuales; femeninos y masculinos; colectivos; institucionales; etc.), obras y manifestaciones culturales del Ecuador, y relacionarlos con sus contextos históricos y sociales', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.5', 'Identificar y describir distintos tipos de manifestaciones y productos culturales y artísticos utilizando un lenguaje técnico, expresando puntos de vista personales, y mostrando una actitud de escucha y receptividad hacia las opiniones de otras personas', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.6', 'Reconocer y explicar diferentes maneras de entender y representar una idea, un sentimiento o una emoción en obras y manifestaciones artísticas y culturales de distintos momentos históricos y de diversas culturas', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.7', 'Analizar y valorar producciones artísticas y eventos culturales usando criterios técnicos y reconociendo las emociones que estos suscitan, y escribir críticas o comentarios para un periódico escolar, un blog personal o colectivo, una red social, etc., adecuando el lenguaje al medio utilizado', 'BGU', 'I.ECA.5.1.1. Reconoce y describe los elementos, personajes, símbolos, técnicas e ideas principales de producciones artísticas de distintas épocas y culturas, y las asocia con formas de pensar, movimientos estéticos y modas. (I.2., S.3.) I.ECA.5.1.2. Identifica la presencia de las mujeres en algunas manifestaciones culturales y artísticas, e infiere y describe sus funciones (autoras, intérpretes, directoras, artesanas, presentes como motivo de representación, etc.). (I.4., S.2.) Investiga con autonomía manifestaciones culturales y artísticas de distintas épocas y contextos, y utiliza adecuadamente la información recogida de diferentes fuentes, en la elaboración de críticas escritas, usando un lenguaje apropiado. (Ref. I.E- CA.5.1.3.) (I.2., J.3.) I.ECA.5.1.4. Demuestra un profundo entendimiento de sí mismo, reflejado en la capacidad de identificar sus fortalezas y debilidades, establecer metas claras y realistas, gestionar sus emociones de manera efectiva y tomar decisiones conscientes basadas en sus valores. (I.2.)'),
  ((select id from asignaturas where codigo = 'ECA'), 'ECA.5.3.9', 'Buscar información sobre distintas formas de expresión en el arte contemporáneo (arte de acción, body art, instalaciones, happening, video arte, acción poética, performance, etc.) y elaborar una presentación o cartel (impreso o digital) que reúna los datos más importantes y algunas imágenes o videos ilustrativos', 'BGU', null),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.1', 'Reconocer a los juegos como manifestaciones constantes en la historia del hombre y relacionarlas con sus contextos de origen, su cultura específica y los sentidos y significados que le permiten a sus participantes convertirlos en una posible práctica recreativa', 'BGU', 'I.EF.5.1.1. Establece relaciones entre diferentes juegos, sus contextos de origen, los sentidos y significados que le otorgan los participantes durante su participación y el impacto en la construcción de la identidad corporal y las dimensiones social, cognitiva, motriz y afectiva de los sujetos. (J.1., S.2.) I.EF.5.1.2. Participa en diferentes juegos reconociendo las diferencias individuales, su competencia motriz y la necesidad de cooperar con pares, identificando las dificultades y posibilidades que representa trabajar en equipo. (J.4., I.4.) I.EF.5.1.3. Elabora estrategias y tácticas colectivas que le permitan alcanzar el objetivo del juego antes que su adversario y reconocer el valor del trabajo en equipo antes y durante su participación en juegos, a partir del reconocimiento de las diferencias individuales. (I.4.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.2', 'Reconocer cómo impactan los juegos en las diferentes dimensiones del sujeto, en la social (como facilitador de relaciones interpersonales), en la motriz (su influencia como motivador en el desarrollo de las capacidades coordinativas y condicionales), en la afectiva (la presencia de las emociones al jugar), en la cognitiva (en la toma de decisiones a la hora de resolver los problemas que le presenta el juego), etc', 'BGU', 'I.EF.5.1.1. Establece relaciones entre diferentes juegos, sus contextos de origen, los sentidos y significados que le otorgan los participantes durante su participación y el impacto en la construcción de la identidad corporal y las dimensiones social, cognitiva, motriz y afectiva de los sujetos. (J.1., S.2.) I.EF.5.1.2. Participa en diferentes juegos reconociendo las diferencias individuales, su competencia motriz y la necesidad de cooperar con pares, identificando las dificultades y posibilidades que representa trabajar en equipo. (J.4., I.4.) I.EF.5.1.3. Elabora estrategias y tácticas colectivas que le permitan alcanzar el objetivo del juego antes que su adversario y reconocer el valor del trabajo en equipo antes y durante su participación en juegos, a partir del reconocimiento de las diferencias individuales. (I.4.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.3', 'Identificar y participar de juegos modificados (de bate y campo, de cancha dividida, de blanco y diana y de invasión), cooperativos (como categoría que involucra otros juegos), reconociendo diferencias y similitudes con prácticas deportivas y maneras en que participa/juega para alcanzar sus objetivos, utilizando tácticas y estrategias posibles y realizando adecuaciones que considere necesarias', 'BGU', 'I.EF.5.1.1. Establece relaciones entre diferentes juegos, sus contextos de origen, los sentidos y significados que le otorgan los participantes durante su participación y el impacto en la construcción de la identidad corporal y las dimensiones social, cognitiva, motriz y afectiva de los sujetos. (J.1., S.2.) I.EF.5.1.2. Participa en diferentes juegos reconociendo las diferencias individuales, su competencia motriz y la necesidad de cooperar con pares, identificando las dificultades y posibilidades que representa trabajar en equipo. (J.4., I.4.) I.EF.5.1.3. Elabora estrategias y tácticas colectivas que le permitan alcanzar el objetivo del juego antes que su adversario y reconocer el valor del trabajo en equipo antes y durante su participación en juegos, a partir del reconocimiento de las diferencias individuales. (I.4.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.1.5', 'Participar de juegos colectivos reconociendo la importancia del trabajo en equipo (posibilidades y dificultades), de cooperar y oponerse y el papel de la comunicación motriz entre los jugadores, para resolver diferentes situaciones de juego y alcanzar sus objetivos', 'BGU', 'I.EF.5.1.1. Establece relaciones entre diferentes juegos, sus contextos de origen, los sentidos y significados que le otorgan los participantes durante su participación y el impacto en la construcción de la identidad corporal y las dimensiones social, cognitiva, motriz y afectiva de los sujetos. (J.1., S.2.) I.EF.5.1.2. Participa en diferentes juegos reconociendo las diferencias individuales, su competencia motriz y la necesidad de cooperar con pares, identificando las dificultades y posibilidades que representa trabajar en equipo. (J.4., I.4.) I.EF.5.1.3. Elabora estrategias y tácticas colectivas que le permitan alcanzar el objetivo del juego antes que su adversario y reconocer el valor del trabajo en equipo antes y durante su participación en juegos, a partir del reconocimiento de las diferencias individuales. (I.4.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.1', 'Reconocer la diferencia entre las prácticas gimnásticas como prácticas sistemáticas (para mejorar la condición física: capacidades coordinativas y condicionales, flexibilidad, velocidad, resistencia y fuerza) y la práctica gimnástica como práctica deportiva (aeróbica, artística, rítmica, acrosport, entre otras) para poder elegir cómo realizarlas de manera consciente, segura y saludable', 'BGU', 'I.EF.5.2.1. Mejora su condición física de manera segura, sistemática y consciente a partir de la construcción de ejercicios y planes básicos, en función de los objetivos a alcanzar. (I.2., S.3.) I.EF.5.2.2. Construye ejercicios, ejecuta movimientos, maneja objetos y optimiza su respiración y posturas, a partir del reconocimiento de su dominio corporal. (J.4., I.4.) I.EF.5.2.3. Establece diferencias entre las prácticas gimnasticas y las prácticas deportivas, reconociendo las demandas de las mismas y la necesidad de mejorar su condición física para participar en ellas de manera segura, placentera y consciente. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.2', 'Reconocer la necesidad de mejorar de modo saludable la condición física (capacidad que tienen los sujetos para realizar actividad física) para favorecer la participación en diferentes prácticas corporales, así como en acciones cotidianas', 'BGU', 'I.EF.5.2.1. Mejora su condición física de manera segura, sistemática y consciente a partir de la construcción de ejercicios y planes básicos, en función de los objetivos a alcanzar. (I.2., S.3.) I.EF.5.2.2. Construye ejercicios, ejecuta movimientos, maneja objetos y optimiza su respiración y posturas, a partir del reconocimiento de su dominio corporal. (J.4., I.4.) I.EF.5.2.3. Establece diferencias entre las prácticas gimnasticas y las prácticas deportivas, reconociendo las demandas de las mismas y la necesidad de mejorar su condición física para participar en ellas de manera segura, placentera y consciente. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.3', 'Construir ejercicios que mejoren la condición física y elaborar entrenamientos básicos para ponerlos en práctica, tomando como punto de partida su estado de inicio y las prácticas corporales hacia las cuales están orientados', 'BGU', 'I.EF.5.2.1. Mejora su condición física de manera segura, sistemática y consciente a partir de la construcción de ejercicios y planes básicos, en función de los objetivos a alcanzar. (I.2., S.3.) I.EF.5.2.2. Construye ejercicios, ejecuta movimientos, maneja objetos y optimiza su respiración y posturas, a partir del reconocimiento de su dominio corporal. (J.4., I.4.) I.EF.5.2.3. Establece diferencias entre las prácticas gimnasticas y las prácticas deportivas, reconociendo las demandas de las mismas y la necesidad de mejorar su condición física para participar en ellas de manera segura, placentera y consciente. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.2.5', 'Reconocer posibilidades de dominio corporal en la ejecución de movimientos y manejo de objetos durante las prácticas gimnásticas, para mejorarlos de manera consciente, segura y saludable', 'BGU', 'I.EF.5.2.1. Mejora su condición física de manera segura, sistemática y consciente a partir de la construcción de ejercicios y planes básicos, en función de los objetivos a alcanzar. (I.2., S.3.) I.EF.5.2.2. Construye ejercicios, ejecuta movimientos, maneja objetos y optimiza su respiración y posturas, a partir del reconocimiento de su dominio corporal. (J.4., I.4.) I.EF.5.2.3. Establece diferencias entre las prácticas gimnasticas y las prácticas deportivas, reconociendo las demandas de las mismas y la necesidad de mejorar su condición física para participar en ellas de manera segura, placentera y consciente. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.1', 'Reconocer las prácticas corporales expresivo-comunicativas como producciones valiosas e identitarias para sus protagonistas (con orígenes, contextos de producción y sentidos/ significados), y a la vez como posibles favorecedoras de la socialización y vinculación entre pares y con la cultura', 'BGU', 'I.EF.5.3.1. Combina prácticas corporales expresivo-comunicativas reconociendo las demandas, los sentidos y significados para los protagonistas, durante la comunicación e intercambio de mensajes corporales. (I.1., S.2.) I.EF.5.3.2. Participa en la construcción de creaciones escénicas colectivas, reconociendo a las prácticas corporales expresivo-comunicativas como producciones valiosas para la cultura, los contextos y los sujetos. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.2', 'Explorar e identificar diferentes tipos de danzas (tradicionales, populares, contemporáneas, entre otras), sus pasos básicos y sus coreografías y las posibilidades de crear nuevas y propias formas de danzar y expresarse corporalmente', 'BGU', 'I.EF.5.4.1. Construye colectivamente espacios de trabajo respetuosos que le posicionen como protagonista y/o espectador y que favorezcan la creación de manifestaciones no estereotipadas ni hegemónicas, mediante el lenguaje corporal. (J.2., S.1.) I.EF.5.4.2. Crea nuevas formas de danzar, utilizando acciones y secuencias con intencionalidad expresiva, y las diferencias de las danzas convencionales, a partir de las demandas que le generan cada una. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.3', 'Identificar los requerimientos (motores, emocionales, cognitivos, entre otros) que presentan diferentes prácticas expresivo-comunicativas y vincularlos con sus características (pasos básicos, música, duración, coreografía), para tomar decisiones sobre los modos de participación en ellas según los objetivos individuales y colectivos', 'BGU', null),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.4', 'Identificar y producir creaciones escénicas colectivas, vinculando más de una práctica corporal (como lo hacen el circo, la murga, los carnavales, entre otras), para crear y comunicar mensajes', 'BGU', 'I.EF.5.3.1. Combina prácticas corporales expresivo-comunicativas reconociendo las demandas, los sentidos y significados para los protagonistas, durante la comunicación e intercambio de mensajes corporales. (I.1., S.2.) I.EF.5.3.2. Participa en la construcción de creaciones escénicas colectivas, reconociendo a las prácticas corporales expresivo-comunicativas como producciones valiosas para la cultura, los contextos y los sujetos. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.5', 'Crear acciones y secuencias motrices utilizando diferentes recursos expresivos (intencionalidad expresiva de diferentes movimientos, según tiempo y espacio: lento-rápido, simultaneo-alternado, continuo-discontinuo, atrás-adelante, otros), desde la necesidad propia de manifestarse mediante el lenguaje corporal para enriquecer las posibilidades de comunicación individual y colectiva', 'BGU', 'I.EF.5.4.1. Construye colectivamente espacios de trabajo respetuosos que le posicionen como protagonista y/o espectador y que favorezcan la creación de manifestaciones no estereotipadas ni hegemónicas, mediante el lenguaje corporal. (J.2., S.1.) I.EF.5.4.2. Crea nuevas formas de danzar, utilizando acciones y secuencias con intencionalidad expresiva, y las diferencias de las danzas convencionales, a partir de las demandas que le generan cada una. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.3.6', 'Diferenciar los roles de espectadores y protagonistas, construyendo maneras de participación respetuosa en ambos, para transferirlas a situaciones en la vida cotidiana', 'BGU', 'I.EF.5.4.1. Construye colectivamente espacios de trabajo respetuosos que le posicionen como protagonista y/o espectador y que favorezcan la creación de manifestaciones no estereotipadas ni hegemónicas, mediante el lenguaje corporal. (J.2., S.1.) I.EF.5.4.2. Crea nuevas formas de danzar, utilizando acciones y secuencias con intencionalidad expresiva, y las diferencias de las danzas convencionales, a partir de las demandas que le generan cada una. (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.1', 'Participar en diversas prácticas deportivas (individuales, colectivas, abiertas, cerradas, de contacto, entre otras) reconociendo sus diferencias según los ámbitos en que se practican (recreativo, amateur, federativo, alto rendimiento, entre otros), sus objetivos y los modos de alcanzarlos, para poder elegirlas, apropiarlas y continuar practicándolas a lo largo de sus vidas', 'BGU', 'I.EF.5.5.1. Participa en diferentes prácticas deportivas, de manera segura, eficaz y colaborativa, comprendiendo la lógica interna de cada una y las posibilidades de acción que permiten los reglamentos. (J.2., I.4.) I.EF.5.5.2. Participa en diferentes prácticas deportivas, realizando ajustes individuales, colectivos y contextuales (técnicos, tácticos, estratégicos y corporales) necesarios en el trabajo de equipo, percibiendo las sensaciones que le favorecen u obstaculizan el alcance de los objetivos. (J.4., S.4.) I.EF.5.5.3. Realiza prácticas deportivas reconociendo los beneficios que pueden aportar a su salud y a su condición física, valorando el juego limpio y percibiendo las sensaciones que favorecen u obstaculizan su desempeño y participación dentro y fuera de la institución educativa. (J.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.2', 'Participar en prácticas deportivas comprendiendo la lógica interna (principios y acciones tácticas) de cada una y realizando ajustes técnicos, tácticos y estratégicos, en función de las reglas y requerimientos (motores, emocionales, cognitivos, sociales) para su resolución eficaz y confortable', 'BGU', 'I.EF.5.5.1. Participa en diferentes prácticas deportivas, de manera segura, eficaz y colaborativa, comprendiendo la lógica interna de cada una y las posibilidades de acción que permiten los reglamentos. (J.2., I.4.) I.EF.5.5.2. Participa en diferentes prácticas deportivas, realizando ajustes individuales, colectivos y contextuales (técnicos, tácticos, estratégicos y corporales) necesarios en el trabajo de equipo, percibiendo las sensaciones que le favorecen u obstaculizan el alcance de los objetivos. (J.4., S.4.) I.EF.5.5.3. Realiza prácticas deportivas reconociendo los beneficios que pueden aportar a su salud y a su condición física, valorando el juego limpio y percibiendo las sensaciones que favorecen u obstaculizan su desempeño y participación dentro y fuera de la institución educativa. (J.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.3', 'Analizar el reglamento de los deportes y reconocerlo como conjunto de normas producidas por las federaciones, que marcan los límites y oportunidades de actuación, para tomar decisiones sobre los modos de participación que le permitan alcanzar los objetivos de dicha práctica', 'BGU', 'I.EF.5.5.1. Participa en diferentes prácticas deportivas, de manera segura, eficaz y colaborativa, comprendiendo la lógica interna de cada una y las posibilidades de acción que permiten los reglamentos. (J.2., I.4.) I.EF.5.5.2. Participa en diferentes prácticas deportivas, realizando ajustes individuales, colectivos y contextuales (técnicos, tácticos, estratégicos y corporales) necesarios en el trabajo de equipo, percibiendo las sensaciones que le favorecen u obstaculizan el alcance de los objetivos. (J.4., S.4.) I.EF.5.5.3. Realiza prácticas deportivas reconociendo los beneficios que pueden aportar a su salud y a su condición física, valorando el juego limpio y percibiendo las sensaciones que favorecen u obstaculizan su desempeño y participación dentro y fuera de la institución educativa. (J.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.5', 'Reconocer la importancia del trabajo en equipo, la ayuda y la cooperación (como requisito para la oposición), para lograr el objetivo de las prácticas deportivas y poder participar en ellas de manera segura y saludable dentro y fuera del colegio', 'BGU', 'I.EF.5.5.1. Participa en diferentes prácticas deportivas, de manera segura, eficaz y colaborativa, comprendiendo la lógica interna de cada una y las posibilidades de acción que permiten los reglamentos. (J.2., I.4.) I.EF.5.5.2. Participa en diferentes prácticas deportivas, realizando ajustes individuales, colectivos y contextuales (técnicos, tácticos, estratégicos y corporales) necesarios en el trabajo de equipo, percibiendo las sensaciones que le favorecen u obstaculizan el alcance de los objetivos. (J.4., S.4.) I.EF.5.5.3. Realiza prácticas deportivas reconociendo los beneficios que pueden aportar a su salud y a su condición física, valorando el juego limpio y percibiendo las sensaciones que favorecen u obstaculizan su desempeño y participación dentro y fuera de la institución educativa. (J.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.6', 'Participar en diferentes prácticas deportivas utilizando diferentes acciones técnicas y tácticas que favorezcan la continuidad del juego, reconociendo que las ejecuciones técnicas y respuestas tácticas cobran sentido en los contextos de juego (y en función del reglamento)', 'BGU', 'I.EF.5.5.1. Participa en diferentes prácticas deportivas, de manera segura, eficaz y colaborativa, comprendiendo la lógica interna de cada una y las posibilidades de acción que permiten los reglamentos. (J.2., I.4.) I.EF.5.5.2. Participa en diferentes prácticas deportivas, realizando ajustes individuales, colectivos y contextuales (técnicos, tácticos, estratégicos y corporales) necesarios en el trabajo de equipo, percibiendo las sensaciones que le favorecen u obstaculizan el alcance de los objetivos. (J.4., S.4.) I.EF.5.5.3. Realiza prácticas deportivas reconociendo los beneficios que pueden aportar a su salud y a su condición física, valorando el juego limpio y percibiendo las sensaciones que favorecen u obstaculizan su desempeño y participación dentro y fuera de la institución educativa. (J.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.8', 'Reconocer los valores del juego limpio (en función del respeto a los acuerdos y reglas) y participar en prácticas deportivas en coherencia con ellos, para transferir esos valores a situaciones cotidianas', 'BGU', null),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.4.9', 'Comprender la necesidad de una preparación física adecuada y coherente con las prácticas deportivas, en función de sus objetivos (recreativo, federativo, de alto rendimiento) y requerimientos motrices, para minimizar los riesgos de lesiones y optimizar el desempeño seguro en el deporte de que se trate', 'BGU', null),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.1', 'Percibir y tomar conciencia de su estado corporal (respiración, postura temperatura, acciones musculares, posiciones, otros) en movimiento y en reposo, durante la realización de prácticas corporales para mejorar la participación consciente', 'BGU', 'I.EF.5.2.1. Mejora su condición física de manera segura, sistemática y consciente a partir de la construcción de ejercicios y planes básicos, en función de los objetivos a alcanzar. (I.2., S.3.) I.EF.5.2.2. Construye ejercicios, ejecuta movimientos, maneja objetos y optimiza su respiración y posturas, a partir del reconocimiento de su dominio corporal. (J.4., I.4.) I.EF.5.2.3. Establece diferencias entre las prácticas gimnasticas y las prácticas deportivas, reconociendo las demandas de las mismas y la necesidad de mejorar su condición física para participar en ellas de manera segura, placentera y consciente. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.3', 'Reconocer percepciones y sensaciones favorecedoras y obstaculizadoras del deseo de moverse (dolor, fatiga, entusiasmo, placer, entre otras), para tomar decisiones personales que colaboren con la participación sistemática en prácticas corporales', 'BGU', 'I.EF.5.6.2. Explicita las percepciones y sensaciones (dolor, fatiga, entusiasmo, placer, entre otras) que favorecenu obstaculizan su deseo de moverse y la construcción de su competencia motriz, influyendo en la toma de decisiones sobre su participación en prácticas corporales individuales y colectivas. (J.4., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.4', 'Reconocer el impacto de las representaciones sociales sobre el “lo femenino” y “lo masculino” en la constitución de la identidad corporal, para analizar críticamente sus sentidos y significados como facilitadores u obstaculizadores de la construcción de la competencia motriz', 'BGU', 'I.EF.5.1.1. Establece relaciones entre diferentes juegos, sus contextos de origen, los sentidos y significados que le otorgan los participantes durante su participación y el impacto en la construcción de la identidad corporal y las dimensiones social, cognitiva, motriz y afectiva de los sujetos. (J.1., S.2.) I.EF.5.1.2. Participa en diferentes juegos reconociendo las diferencias individuales, su competencia motriz y la necesidad de cooperar con pares, identificando las dificultades y posibilidades que representa trabajar en equipo. (J.4., I.4.) I.EF.5.1.3. Elabora estrategias y tácticas colectivas que le permitan alcanzar el objetivo del juego antes que su adversario y reconocer el valor del trabajo en equipo antes y durante su participación en juegos, a partir del reconocimiento de las diferencias individuales. (I.4.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.5', 'Reconocer la influencia de las percepciones de sí y de las demás personas sobre el propio desempeño, para analizarlas críticamente y construir posibilidades de participación', 'BGU', null),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.5.6', 'Analizar críticamente los vínculos entre los intereses y valores que portan los modelos estéticos hegemónicos y estereotipos de movimientos en relación a la singularidad de los sujetos y sus contextos', 'BGU', 'I.EF.5.7.2. Explicita la influencia que las etiquetas sociales, los modelos estéticos, las percepciones sobre la propia imagen y los movimientos estereotipados tienen sobre la singularidad de los sujetos y la construcción de su identidad corporal. (J.3., S.3.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.1', 'Identificar las demandas de las prácticas corporales para mejorar la condición física de base y el logro de los objetivos personales', 'BGU', 'I.EF.5.3.1. Combina prácticas corporales expresivo-comunicativas reconociendo las demandas, los sentidos y significados para los protagonistas, durante la comunicación e intercambio de mensajes corporales. (I.1., S.2.) I.EF.5.3.2. Participa en la construcción de creaciones escénicas colectivas, reconociendo a las prácticas corporales expresivo-comunicativas como producciones valiosas para la cultura, los contextos y los sujetos. (J.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.3', 'Reconocer los beneficios que la actividad física puede aportar a su salud y su condición física, como un estado que puede mejorarse o deteriorarse en función del tipo y pertinencia de las actividades físicas y prácticas corporales que realiza', 'BGU', 'I.EF.5.8.1. Identifica las demandas de las prácticas corporales y las relaciona con el impacto en la salud, asumiendo una actitud crítica y reflexiva sobre sus propias prácticas cuidando de sí, de pares y del ambiente. (J.3., S.3.) I.EF.5.8.2. Plantea objetivos personales de mejora de su condición física, a partir de la identificación de los beneficios que, una determinada actividad física realizada pertinentemente, suponen para su salud. (I.2., S.3.) I.EF.5.8.3. Actúa de manera coherente en situaciones simuladas de siniestros de tránsito, asumiendo distintos roles en situaciones de emergencia de manera segura. (J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.4', 'Reconocer la importancia de las diferencias individuales durante la participación en diferentes prácticas corporales, para identificar las maneras más saludables de alcanzar objetivos personales', 'BGU', 'I.EF.5.9.1. Realiza prácticas corporales de manera sistemática, saludable y reflexiva, tomando en consideración las diferencias individuales y los controles médicos. (J.3., S.3.) I.EF.5.9.2. Construye planes de trabajo físico básicos, teniendo en cuenta los resultados de los controles médicos. (J.4., I.4.).'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.5', 'Reconocer la importancia de los controles médicos previos y posteriores a la realización de prácticas corporales sistemáticas, como promotores de condiciones de participación responsable y saludable', 'BGU', 'I.EF.5.9.1. Realiza prácticas corporales de manera sistemática, saludable y reflexiva, tomando en consideración las diferencias individuales y los controles médicos. (J.3., S.3.) I.EF.5.9.2. Construye planes de trabajo físico básicos, teniendo en cuenta los resultados de los controles médicos. (J.4., I.4.).'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.6', 'Elaborar y poner en práctica planes básicos de trabajo propios, para mejorar la condición física de partida en función de los objetivos a alcanzar, los conocimientos sobre las actividades pertinentes para hacerlo y los cuidados a tener en cuenta para minimizar riesgos y optimizar resultados positivos', 'BGU', 'I.EF.5.9.1. Realiza prácticas corporales de manera sistemática, saludable y reflexiva, tomando en consideración las diferencias individuales y los controles médicos. (J.3., S.3.) I.EF.5.9.2. Construye planes de trabajo físico básicos, teniendo en cuenta los resultados de los controles médicos. (J.4., I.4.).'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.7', 'Reconocer la importancia del cuidado personal, comunitario y ambiental (seguridad e higiene) antes, durante y luego de la realización de diferentes prácticas corporales, para favorecer que la participación sea segura, saludable y placentera', 'BGU', 'I.EF.5.8.1. Identifica las demandas de las prácticas corporales y las relaciona con el impacto en la salud, asumiendo una actitud crítica y reflexiva sobre sus propias prácticas cuidando de sí, de pares y del ambiente. (J.3., S.3.) I.EF.5.8.2. Plantea objetivos personales de mejora de su condición física, a partir de la identificación de los beneficios que, una determinada actividad física realizada pertinentemente, suponen para su salud. (I.2., S.3.) I.EF.5.8.3. Actúa de manera coherente en situaciones simuladas de siniestros de tránsito, asumiendo distintos roles en situaciones de emergencia de manera segura. (J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'EF'), 'EF.5.6.8', 'Discriminar las acciones adecuadas a seguir en caso de siniestros de tránsito mediante simulaciones, asegurando una participación segura y efectiva en situaciones de emergencia', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.1', 'Describir y explicar los conceptos básicos financieros de un emprendimiento, tales como ingresos, costos, gastos e inversión, punto de equilibrio y sus proyecciones futuras como elemento fundamental para las proyecciones', 'BGU', 'Describe proyecciones financieras y el capital de trabajo de un emprendimiento basándose en conceptos financieros básicos. (Ref.I.EG.5.1.1) (I.1., I.4.) Describe el capital de trabajo de un emprendimiento basándose en conceptos financieros básicos. (Ref.I.EG.5.1.2.) (I.1., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.10', 'Elaborar un estado de pérdidas y ganancias básico mediante la aplicación de las cuentas contables y la ecuación contable en un caso de estudio', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.2', 'Distinguir los diferentes tipos de costos y gastos que puede tener un emprendimiento para determinar detenidamente el capital de trabajo necesario para un emprendimiento', 'BGU', 'Describe proyecciones financieras y el capital de trabajo de un emprendimiento basándose en conceptos financieros básicos. (Ref.I.EG.5.1.1) (I.1., I.4.) Describe el capital de trabajo de un emprendimiento basándose en conceptos financieros básicos. (Ref.I.EG.5.1.2.) (I.1., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.3', 'Identificar la obligatoriedad jurídica de llevar contabilidad de acuerdo con lo establecido por las normas tributarias como elemento fundamental para determinar la forma de llevar la contabilidad', 'BGU', 'I.EG.5.2.1. Ordena las cuentas contables de acuerdo con la naturaleza de la función de los asientos contables en aquellos emprendimientos obligados a llevar contabilidad, tomando en cuenta las normas tributarias establecidas por la autoridad competente. (I.4., J.2.) I.EG.5.2.2. Registra transacciones en las cuentas contables bajo el principio de partida doble, según la normativa contable vigente. (J.2., I.4.) I.EG.5.2.3. Construye estados financieros (balance general y estado de pérdidas y ganancias) aplicando técnicas contables y la normativa vigente. (I.4., J.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.4', 'Deducir la importancia de la contabilidad como elemento de control financiero del emprendimiento', 'BGU', 'I.EG.5.2.1. Ordena las cuentas contables de acuerdo con la naturaleza de la función de los asientos contables en aquellos emprendimientos obligados a llevar contabilidad, tomando en cuenta las normas tributarias establecidas por la autoridad competente. (I.4., J.2.) I.EG.5.2.2. Registra transacciones en las cuentas contables bajo el principio de partida doble, según la normativa contable vigente. (J.2., I.4.) I.EG.5.2.3. Construye estados financieros (balance general y estado de pérdidas y ganancias) aplicando técnicas contables y la normativa vigente. (I.4., J.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.5', 'Explicar las principales normas contables relacionadas con la partida doble para establecer los impactos en las cuentas', 'BGU', 'I.EG.5.2.1. Ordena las cuentas contables de acuerdo con la naturaleza de la función de los asientos contables en aquellos emprendimientos obligados a llevar contabilidad, tomando en cuenta las normas tributarias establecidas por la autoridad competente. (I.4., J.2.) I.EG.5.2.2. Registra transacciones en las cuentas contables bajo el principio de partida doble, según la normativa contable vigente. (J.2., I.4.) I.EG.5.2.3. Construye estados financieros (balance general y estado de pérdidas y ganancias) aplicando técnicas contables y la normativa vigente. (I.4., J.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.6', 'Clasificar las principales cuentas contables con su respectivo nombre para personificarlas, mediante la determinación de la naturaleza de su función en los asientos contables, tales como caja, bancos, cuentas por cobrar, inventarios, activos fijos, depreciación, capital, cuentas por pagar, préstamos bancarios, capital', 'BGU', 'I.EG.5.2.1. Ordena las cuentas contables de acuerdo con la naturaleza de la función de los asientos contables en aquellos emprendimientos obligados a llevar contabilidad, tomando en cuenta las normas tributarias establecidas por la autoridad competente. (I.4., J.2.) I.EG.5.2.2. Registra transacciones en las cuentas contables bajo el principio de partida doble, según la normativa contable vigente. (J.2., I.4.) I.EG.5.2.3. Construye estados financieros (balance general y estado de pérdidas y ganancias) aplicando técnicas contables y la normativa vigente. (I.4., J.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.7', 'Identificar los componentes básicos del activo, pasivo, patrimonio, ingresos, costos y gastos, de acuerdo con la normativa contable, para clasificar adecuadamente las cuentas contables', 'BGU', 'I.EG.5.2.1. Ordena las cuentas contables de acuerdo con la naturaleza de la función de los asientos contables en aquellos emprendimientos obligados a llevar contabilidad, tomando en cuenta las normas tributarias establecidas por la autoridad competente. (I.4., J.2.) I.EG.5.2.2. Registra transacciones en las cuentas contables bajo el principio de partida doble, según la normativa contable vigente. (J.2., I.4.) I.EG.5.2.3. Construye estados financieros (balance general y estado de pérdidas y ganancias) aplicando técnicas contables y la normativa vigente. (I.4., J.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.8', 'Interpretar las cuentas contables mediante la identificación de los cambios que causan las transacciones en los activos, pasivos y patrimonios, reflejados en la cuenta por partida doble', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.1.9', 'Elaborar un balance general básico mediante la aplicación de los principios, conceptos, técnicas contables y la normatividad vigente', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.1', 'Elaborar un mapeo de los requisitos legales básicos para iniciar actividades de emprendimiento que permitan formalizarlo', 'BGU', 'I.EG.5.3.1. Comprende la importancia de generar una cultura tanto tributaria como de responsabilidad legal en cualquier emprendimiento, para validar sus operaciones en el mercado. (S.1., I.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.2', 'Identificar las obligaciones legales que debe cumplir un emprendedor como elemento fundamental para la operación del mismo. E', 'BGU', 'I.EG.5.3.1. Comprende la importancia de generar una cultura tanto tributaria como de responsabilidad legal en cualquier emprendimiento, para validar sus operaciones en el mercado. (S.1., I.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.4', 'Aplicar los conocimientos tributarios en el llenado de los formularios básicos del SRI (RISE, IVA e Impuesto a la Renta)', 'BGU', 'I.EG.5.3.1. Comprende la importancia de generar una cultura tanto tributaria como de responsabilidad legal en cualquier emprendimiento, para validar sus operaciones en el mercado. (S.1., I.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.2.5', 'Comprender los factores que afectan el poder adquisitivo del dinero, el impacto de los intereses compuestos en el ahorro evaluando las ventajas y desventajas de diversos productos de inversión', 'BGU', 'I.EG.5.3.1. Comprende la importancia de generar una cultura tanto tributaria como de responsabilidad legal en cualquier emprendimiento, para validar sus operaciones en el mercado. (S.1., I.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.1', 'Proponer y definir productos o servicios determinados por necesidades de su entorno', 'BGU', 'I.EG.5.4.1. Determina, en una zona geográfica, la necesidad de un determinado bien o servicio para convertirla en su cliente frecuente. (S.4., S.1.) I.EG.5.4.2. Ejecuta investigaciones de campo y diseña instrumentos de investigación para seleccionar las ideas de emprendimiento que presenten mayor factibilidad en el mercado. (I.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.10', 'Analizar los delitos financieros existentes, como el robo de identidad, fraudes, estafas, entre otros, para tomar decisiones informadas y precautelar su integridad', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.2', 'Describir y explicar los componentes del diseño de la investigación de campo para obtener información certera sobre el tema que se desea investigar o profundizar', 'BGU', 'I.EG.5.4.1. Determina, en una zona geográfica, la necesidad de un determinado bien o servicio para convertirla en su cliente frecuente. (S.4., S.1.) I.EG.5.4.2. Ejecuta investigaciones de campo y diseña instrumentos de investigación para seleccionar las ideas de emprendimiento que presenten mayor factibilidad en el mercado. (I.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.4', 'Ejecutar una investigación de campo entre los potenciales clientes/ usuarios determinados para establecer las necesidades de la zona geográfica, de tal manera que se determinen las potenciales ideas de emprendimiento', 'BGU', 'I.EG.5.4.1. Determina, en una zona geográfica, la necesidad de un determinado bien o servicio para convertirla en su cliente frecuente. (S.4., S.1.) I.EG.5.4.2. Ejecuta investigaciones de campo y diseña instrumentos de investigación para seleccionar las ideas de emprendimiento que presenten mayor factibilidad en el mercado. (I.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.5', 'Describir los conocimientos estadísticos básicos para tabular los datos recabados en una investigación de campo', 'BGU', 'I.EG.5.5.1. Presenta la información de mercado (oferta y demanda) a través de la representación gráfica de los datos procesados, en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, y estudios de medidas de tendencia central (media, mediana, moda), así como la información obtenida en la investigación de campo de forma resumida y concisa, de tal manera que se facilite la toma de decisiones. (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.6', 'Presentar la información obtenida en la investigación de campo de forma resumida y concisa en función de su utilidad para la toma de decisiones', 'BGU', 'I.EG.5.5.1. Presenta la información de mercado (oferta y demanda) a través de la representación gráfica de los datos procesados, en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, y estudios de medidas de tendencia central (media, mediana, moda), así como la información obtenida en la investigación de campo de forma resumida y concisa, de tal manera que se facilite la toma de decisiones. (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.7', 'Analizar estadísticamente la información de mercado (oferta y demanda) a partir de la representación gráfica de los datos procesados en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, estudios de medidas de tendencia central (media, mediana, moda)', 'BGU', 'I.EG.5.5.1. Presenta la información de mercado (oferta y demanda) a través de la representación gráfica de los datos procesados, en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, y estudios de medidas de tendencia central (media, mediana, moda), así como la información obtenida en la investigación de campo de forma resumida y concisa, de tal manera que se facilite la toma de decisiones. (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.3.8', 'Utilizar metodologías para interpretar datos estadísticos como fundamento para la toma de decisiones y la selección de las ideas de emprendimiento con mayor probabilidad de éxito', 'BGU', 'I.EG.5.5.1. Presenta la información de mercado (oferta y demanda) a través de la representación gráfica de los datos procesados, en tablas, gráficas, histogramas, cálculo de frecuencias, diagramas, y estudios de medidas de tendencia central (media, mediana, moda), así como la información obtenida en la investigación de campo de forma resumida y concisa, de tal manera que se facilite la toma de decisiones. (I.2., I.4.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.1', 'Aplicar en un emprendimiento los elementos básicos de los principios de administración: planeación, organización, integración, dirección y control para generar las habilidades directivas requeridas para un emprendedor', 'BGU', 'I.EG.5.6.1. Valora, de acuerdo con un criterio administrativo, el cumplimiento de objetivos financieros, así como la responsabilidad social en la planificación de los recursos humanos (estructura organizacional, proceso de contratación, capacitación, deberes y derechos laborales, despido) y diagrama una estructura organizacional óptima para un emprendimiento. (I.4, S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.10', 'Reconocer los factores financieros que conducen a condiciones de equidad social e igualdad de ingresos', 'BGU', 'I.EG.5.7.1. Comprueba la rentabilidad de un emprendimiento a partir del análisis de indicadores económicos (inflación, oferta, demanda, mercado, empleo, etc.), para favorecer la toma de decisiones. (I.2., I.1.) I.EG.5.7.2. Analiza la rentabilidad de un emprendimiento a partir de sus costos marginales (costos hundidos). (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.2', 'Desarrollar criterios sobre administración para generar eficacia en los emprendimientos', 'BGU', 'I.EG.5.6.1. Valora, de acuerdo con un criterio administrativo, el cumplimiento de objetivos financieros, así como la responsabilidad social en la planificación de los recursos humanos (estructura organizacional, proceso de contratación, capacitación, deberes y derechos laborales, despido) y diagrama una estructura organizacional óptima para un emprendimiento. (I.4, S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.3', 'Identificar, valorar e implementar el concepto de responsabilidad social en el desarrollo de emprendimientos como elemento fundamental para la generación de emprendimientos con carácter social', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.4', 'Analizar conceptos básicos de economía (Inflación, Oferta, Demanda, Mercado, Empleo, etc.) con el fin de establecer su impacto en las decisiones del emprendimiento', 'BGU', 'I.EG.5.7.1. Comprueba la rentabilidad de un emprendimiento a partir del análisis de indicadores económicos (inflación, oferta, demanda, mercado, empleo, etc.), para favorecer la toma de decisiones. (I.2., I.1.) I.EG.5.7.2. Analiza la rentabilidad de un emprendimiento a partir de sus costos marginales (costos hundidos). (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.5', 'Aplicar principios básicos de microeconomía para el desarrollo de emprendimientos como elemento para la toma de decisiones', 'BGU', 'I.EG.5.7.1. Comprueba la rentabilidad de un emprendimiento a partir del análisis de indicadores económicos (inflación, oferta, demanda, mercado, empleo, etc.), para favorecer la toma de decisiones. (I.2., I.1.) I.EG.5.7.2. Analiza la rentabilidad de un emprendimiento a partir de sus costos marginales (costos hundidos). (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.7', 'Generar herramientas para gestionar el estrés y disminuir sus efectos nocivos en el bienestar físico y emocional, durante la toma de decisiones en la planeación y ejecución de sus emprendimientos', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.4.9', 'Comprender el impacto de las tasas de interés, los tipos de cambio, la volatilidad del mercado, los impuestos y la inflación en las decisiones financieras', 'BGU', 'I.EG.5.7.1. Comprueba la rentabilidad de un emprendimiento a partir del análisis de indicadores económicos (inflación, oferta, demanda, mercado, empleo, etc.), para favorecer la toma de decisiones. (I.2., I.1.) I.EG.5.7.2. Analiza la rentabilidad de un emprendimiento a partir de sus costos marginales (costos hundidos). (I.2., S.3.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.1', 'Determinar la necesidad que la zona geográfica posee y la forma como el emprendimiento satisface dicha necesidad, como elemento fundamental para seleccionar una idea de negocio', 'BGU', 'I.EG.5.4.1. Determina, en una zona geográfica, la necesidad de un determinado bien o servicio para convertirla en su cliente frecuente. (S.4., S.1.) I.EG.5.4.2. Ejecuta investigaciones de campo y diseña instrumentos de investigación para seleccionar las ideas de emprendimiento que presenten mayor factibilidad en el mercado. (I.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.11', 'Aplicar metodologías para elaborar una proyección de ingresos (incluyendo incrementos paulatinos y ciclicidad), considerando las unidades vendidas y los precios de venta, para establecer el monto de ingresos del nuevo emprendimiento', 'BGU', 'I.EG.5.10.1. Aplica las TIC para proyectar costos y gastos, calcular el punto de equilibrio del emprendimiento y el margen de contribución del producto o servicio ofertado. (I.3., I.1.) I.EG.5.10.2. Aplica las TIC en proyecciones de efectivo con experiencia en incrementos paulatinos y ciclicidad del mercado (considerando las unidades vendidas y los precios de venta), para establecer el monto de ingresos futuros del emprendimiento. (I.3., I.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.12', 'Utilizar metodologías para elaborar proyecciones de costos y gastos que permitan establecer el monto necesario para cumplir con estas obligaciones de fondos futuros', 'BGU', 'I.EG.5.10.1. Aplica las TIC para proyectar costos y gastos, calcular el punto de equilibrio del emprendimiento y el margen de contribución del producto o servicio ofertado. (I.3., I.1.) I.EG.5.10.2. Aplica las TIC en proyecciones de efectivo con experiencia en incrementos paulatinos y ciclicidad del mercado (considerando las unidades vendidas y los precios de venta), para establecer el monto de ingresos futuros del emprendimiento. (I.3., I.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.13', 'Utilizar hojas electrónicas para realizar las proyecciones utilizando las Tics de manera que se facilite su elaboración', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.14', 'Elaborar un plan de ingresos y egresos del futuro emprendimiento que permita la evaluación cuantitativa del mismo', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.15', 'Calcular el margen de contribución del producto o servicio en el emprendimiento', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.16', 'Calcular el punto de equilibrio de una empresa a través de la identificación de costos unitarios', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.2', 'Exponer de forma sintetizada y sencilla del bien o servicio seleccionada por el estudiante (idea de emprendimiento) y sus características principales, de tal manera que en un lapso muy corto genere impacto entre quienes escuchan', 'BGU', 'I.EG.5.8.1. Realiza una mezcla adecuada de las variables de mercado (producto, precio, plaza, promoción y personalización) para un bien o servicio nuevo que presenta a un segmento de mercado específico mediante mecanismos de comunicación eficaces. (I.3., S.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.4', 'Describir detalladamente el proceso operacional o productivo del nuevo emprendimiento con todos los componentes y recursos requeridos (recursos humanos y recursos materiales) para asegurar la fabricación de un producto o la generación de un servicio de alta calidad', 'BGU', 'Especifica detalladamente las actividades de la planificación de producción (recursos humanos y materiales) para que un emprendimiento sea de calidad y productivo. (Ref. I.EG.5.9.1.) (I.1., S.1.) I.EG.5.9.2. Determina la cantidad de bienes o servicios que se debe producir debido a la proporción de los costos de producción (costos fijos, variables, directos e indirectos) y los gastos incurridos, para que el emprendimiento sea productivo. (I.1., S.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.5', 'Determinar el monto de los bienes que se requieren a fin de establecer el valor de la inversión necesaria del nuevo emprendimiento', 'BGU', 'Especifica detalladamente las actividades de la planificación de producción (recursos humanos y materiales) para que un emprendimiento sea de calidad y productivo. (Ref. I.EG.5.9.1.) (I.1., S.1.) I.EG.5.9.2. Determina la cantidad de bienes o servicios que se debe producir debido a la proporción de los costos de producción (costos fijos, variables, directos e indirectos) y los gastos incurridos, para que el emprendimiento sea productivo. (I.1., S.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.6', 'Determinar el costo de producción de los bienes o el costo de los servicios como elemento fundamental para conocer los gastos requeridos para la operación', 'BGU', 'Especifica detalladamente las actividades de la planificación de producción (recursos humanos y materiales) para que un emprendimiento sea de calidad y productivo. (Ref. I.EG.5.9.1.) (I.1., S.1.) I.EG.5.9.2. Determina la cantidad de bienes o servicios que se debe producir debido a la proporción de los costos de producción (costos fijos, variables, directos e indirectos) y los gastos incurridos, para que el emprendimiento sea productivo. (I.1., S.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.7', 'Identificar los diferentes costos fijos y variables (directos e indirectos) en un ejercicio de bienes o servicios', 'BGU', 'Especifica detalladamente las actividades de la planificación de producción (recursos humanos y materiales) para que un emprendimiento sea de calidad y productivo. (Ref. I.EG.5.9.1.) (I.1., S.1.) I.EG.5.9.2. Determina la cantidad de bienes o servicios que se debe producir debido a la proporción de los costos de producción (costos fijos, variables, directos e indirectos) y los gastos incurridos, para que el emprendimiento sea productivo. (I.1., S.1.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.8', 'Describir y explicar de forma sencilla el segmento de mercado que se desea alcanzar y sus características, para establecer estrategias adecuadas para convertirlo en cliente/usuario', 'BGU', 'I.EG.5.4.1. Determina, en una zona geográfica, la necesidad de un determinado bien o servicio para convertirla en su cliente frecuente. (S.4., S.1.) I.EG.5.4.2. Ejecuta investigaciones de campo y diseña instrumentos de investigación para seleccionar las ideas de emprendimiento que presenten mayor factibilidad en el mercado. (I.1., S.2.)'),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.5.9', 'Establecer las variables de mercado (producto, precio, plaza, promoción y personalización) en el emprendimiento a crearse, que permita satisfacer las necesidades del segmento de mercado seleccionado', 'BGU', null),
  ((select id from asignaturas where codigo = 'EMP'), 'EG.5.6.1', 'Aplicar técnicas básicas para la evaluación financiera de un proyecto de emprendimiento (como análisis de rentabilidad, periodo de recuperación, tasa interna de retorno y valor actual neto) que permitan tomar decisiones sobre su implementación', 'BGU', 'I.EG.5.11.1. Elige el proyecto de emprendimiento con menor riesgo financiero después de analizar la rentabilidad, periodo de recuperación, tasa interna de retorno y valor actual neto. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.1', 'Display an understanding of the relationship between the practices and perspectives of different cultures by recognizing and sharing cross-cultural experiences and ideas', 'BGU', 'I.EFL.5.1.1. Learners can demonstrate an understanding of the integrity of different cultures by sharing experiences and by participating in class activities and discussions in a way that shows empathy and respect for others. (I.3, S.1, S.2, J.1, J3).'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.10', 'Take initiative in a discussion in a positive way by being sensitive to the nuances of peers’ comments, reactions and responses (both verbal and nonverbal)', 'BGU', 'I.EFL.5.1.1. Learners can demonstrate an understanding of the integrity of different cultures by sharing experiences and by participating in class activities and discussions in a way that shows empathy and respect for others. (I.3, S.1, S.2, J.1, J3).'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.11', 'Apply self-correcting and self-monitoring strategies in social and classroom interactions by adjusting presentation and language production to effectively express opinions and make evaluations. (Example: asking questions, starting over, rephrasing, exploring alternative pronunciations, etc.)', 'BGU', 'I.EFL.5.4.1. Learners can communicate effectively using a variety of media and formats, including ICT, by saying things in alternative ways and applying self-correcting and self-monitoring strategies when needed (I1, I.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.2', 'Demonstrate mindfulness, empathy, tolerance and an overall respect for the integrity of cultures in daily classroom activities', 'BGU', 'I.EFL.5.1.1. Learners can demonstrate an understanding of the integrity of different cultures by sharing experiences and by participating in class activities and discussions in a way that shows empathy and respect for others. (I.3, S.1, S.2, J.1, J3).'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.3', 'Find parallels between Ecuadorian cultural and political referents and those of other countries by talking about holidays, symbols, customs and schooling', 'BGU', 'I.EFL.5.2.1. Learners can exhibit an ability to discuss culture by analyzing cultural products and referents from Ecuador and other countries while making informed choices about and taking action on issues of prejudice and discrimination. (I.1, I.2, S.2, J.1, J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.4', 'Identify and interpret how cultural and language patterns in English are used when exchanging ideas on familiar topics according to a B1.2 level. (Example: slang, idioms, humor, levels of formality, etc.)', 'BGU', 'I.EFL.5.3.1. Learners can interpret cultural and language patterns in English, including nonverbal communication, and apply them in appropriate contexts. (I.3, I.4, S.1, S.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.5', 'Identify, discuss and analyze cultural products from Ecuador and beyond and use them to explore the perspectives of the culture', 'BGU', 'I.EFL.5.2.1. Learners can exhibit an ability to discuss culture by analyzing cultural products and referents from Ecuador and other countries while making informed choices about and taking action on issues of prejudice and discrimination. (I.1, I.2, S.2, J.1, J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.6', 'Demonstrate an ability to make informed choices about and take action on issues of prejudice and discrimination', 'BGU', 'I.EFL.5.2.1. Learners can exhibit an ability to discuss culture by analyzing cultural products and referents from Ecuador and other countries while making informed choices about and taking action on issues of prejudice and discrimination. (I.1, I.2, S.2, J.1, J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.7', 'Interpret and demonstrate knowledge of nonverbal and oral communication features by applying them in appropriate contexts. (Example: use of stress, intonation, pace, etc.)', 'BGU', 'I.EFL.5.3.1. Learners can interpret cultural and language patterns in English, including nonverbal communication, and apply them in appropriate contexts. (I.3, I.4, S.1, S.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.8', 'Discover and employ alternative ways of saying things in social and classroom interactions', 'BGU', 'I.EFL.5.4.1. Learners can communicate effectively using a variety of media and formats, including ICT, by saying things in alternative ways and applying self-correcting and self-monitoring strategies when needed (I1, I.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.1.9', 'Communicate information and ideas effectively to diverse audiences using a variety of media and formats', 'BGU', 'I.EFL.5.4.1. Learners can communicate effectively using a variety of media and formats, including ICT, by saying things in alternative ways and applying self-correcting and self-monitoring strategies when needed (I1, I.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.1', 'Deduce the meanings of unfamiliar phrases and words from a context containing familiar elements. (Example: colloquial greetings, exclamations, interjections, etc.)', 'BGU', 'I.EFL.5.5.1. Learners can identify the main idea in a variety of audio recordings (e.g., interviews, radio ads, news reports, etc.) and deduce the meanings of unfamiliar phrases and words in familiar contexts where speech is clear and visuals help support meaning. (I.3, I.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.10', 'Develop an argument well enough to be followed by a peer audience without much difficulty in prepared presentations', 'BGU', 'I.EFL.5.9.1. Learners can present information clearly and influence an audience effectively through well-developed arguments in prepared presentations and other forms of oral communication. (I.2, I.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.11', 'Express opinions on abstract topics, such as film and music, and concrete topics, such as personal experiences, while describing one’s reactions to them and others’ opinions', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.12', 'Use appropriate vocabulary, expressions, language, routines and interaction styles in formal and informal social or academic situations by asking permision, thanking someone, apologizing to friends, giving advice, making a suggestion, etc', 'BGU', 'I.EFL.5.7.1. Learners can communicate clearly and effectively by using appropriate vocabulary and language in a variety of oral interactions for a range of audiences and level appropriate purposes. (I.2, I.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.13', 'Deal with practical, everyday communication demands within familiar contexts, effectively and without undue effort. (Example: meeting people, extending and accepting invitations, exchanging information, giving reasons, asking and answering questions about routines and preferences, etc.)', 'BGU', 'I.EFL.5.6.1. Learners can deal with practical, everyday communication demands in familiar social and academic contexts, such as following directions in class activities and identifying main ideas in other curricular subjects when given sufficient support. (I.1, I.3, S.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.14', 'Request and provide information and assistance orally for personal, social and academic purposes in order to clarify and extend meaning in spoken interactions', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.15', 'Engage in an extended conversation on most general topics and keep it going by expressing and responding to suggestions, opinions, attitudes, advice, feelings, etc', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.2', 'Identify the main idea and some details of recorded news reports, documentaries and interviews reporting on seasonal festivities, environmental issues, food and international customs, climate, weather, etc., where the visuals support the commentary', 'BGU', 'I.EFL.5.5.1. Learners can identify the main idea in a variety of audio recordings (e.g., interviews, radio ads, news reports, etc.) and deduce the meanings of unfamiliar phrases and words in familiar contexts where speech is clear and visuals help support meaning. (I.3, I.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.3', 'Follow main ideas in topics covered in other curricular subjects with the help of visual support, using concepts and vocabulary that have been studied in advance', 'BGU', 'I.EFL.5.6.1. Learners can deal with practical, everyday communication demands in familiar social and academic contexts, such as following directions in class activities and identifying main ideas in other curricular subjects when given sufficient support. (I.1, I.3, S.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.4', 'Follow oral directions in classroom activities and projects and provide directions to peers in selected interactions', 'BGU', 'I.EFL.5.6.1. Learners can deal with practical, everyday communication demands in familiar social and academic contexts, such as following directions in class activities and identifying main ideas in other curricular subjects when given sufficient support. (I.1, I.3, S.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.5', 'Understand the main idea of radio and audio recordings on subjects of personal interest, provided speech is clear', 'BGU', 'I.EFL.5.5.1. Learners can identify the main idea in a variety of audio recordings (e.g., interviews, radio ads, news reports, etc.) and deduce the meanings of unfamiliar phrases and words in familiar contexts where speech is clear and visuals help support meaning. (I.3, I.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.6', 'Use new words and expressions which occur in conversations in the personal and educational domains and make use of such terms and expressions wherever appropriate and necessary', 'BGU', 'I.EFL.5.7.1. Learners can communicate clearly and effectively by using appropriate vocabulary and language in a variety of oral interactions for a range of audiences and level appropriate purposes. (I.2, I.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.7', 'Present information clearly and effectively in a variety of oral forms for a range of audiences and purposes. (Example: summarizing, paraphrasing, personal narratives, research reports, essays, articles, posters, charts and other graphics, etc.)', 'BGU', 'I.EFL.5.9.1. Learners can present information clearly and influence an audience effectively through well-developed arguments in prepared presentations and other forms of oral communication. (I.2, I.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.8', 'Influence an audience effective-ly through persuasion, argument or nego-tiation using conventions and features of English. (Example: precise vocabulary, pronunciation, intonation, presentation strategies, etc.)', 'BGU', 'I.EFL.5.9.1. Learners can present information clearly and influence an audience effectively through well-developed arguments in prepared presentations and other forms of oral communication. (I.2, I.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.2.9', 'Build on others’ ideas when engaged in pair, group or whole-class discussions on personal, social, community and academic topics', 'BGU', 'I.EFL.5.8.1. Learners can respond to and build on other people’s ideas in extended conversations on familiar, social and academic topics by expressing opinions and feelings and clarifying meaning. (I.3, I.4, S.1, J.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.1', 'Find specific predictable information in short, simple texts in a range of age-and level-appropriate topics. (Example: biographies, news articles, narratives, memoirs and personal accounts, formal letters and emails, etc.)', 'BGU', 'I.EFL.5.10.1. Learners can fin specific information and identify the main points in simple, straightforward texts on subjects of personal interest or familiar academic topics while making informed decisions about one’s own reaction to the text. (I.1, I2, S.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.2', 'Identify and use reading strategies to make informative and narrative texts comprehensible and meaningful. (Example: skimming, scanning, previewing, reading for main ideas and details, using structural and context clues, cognates, format, sequence, etc.)', 'BGU', 'I.EFL.5.11.1. Learners can identify and apply a range of reading strategies in order to make texts meaningful and to select information within a text that might be of practical use for one’s own academic needs. (I.1, I.2, I.4, S.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.3', 'Determine the main conclusion in texts which clearly argue a point of view in order to make informed decisions about one’s own opinion and reaction to the text', 'BGU', 'I.EFL.5.10.1. Learners can fin specific information and identify the main points in simple, straightforward texts on subjects of personal interest or familiar academic topics while making informed decisions about one’s own reaction to the text. (I.1, I2, S.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.4', 'Find the most important information in print or online sources in order to support an idea or argument. (Example: Internet search engines, online advertising, online or print timetables, web pages, posters, adverts, catalogues, etc.)', 'BGU', 'Learners can engage with a variety of digital and print texts and resources by evaluating the information in order to find the most appropriate sources to support an idea or argument.(Ref. I.EFL.5.12.1. (I.2, I.4, J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.5', 'Assess, compare and evaluate the quality of written texts and visual presentations using different criteria and ICT tools related to the organization, subject area and purpose of a text. (Examples of text types: editorials, letters to the editor, political speeches, illustrations, charts, advertisements, etc.)', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.6', 'Display an appreciation of the language by interacting and engaging with a variety of digital and print texts and resources and by selecting and evaluating these materials as a means to promote and strengthen literacy skills and language acquisition', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.8', 'Identify and understand the main points in straightforward texts on subjects of personal interest or familiar academic topics', 'BGU', 'I.EFL.5.10.1. Learners can fin specific information and identify the main points in simple, straightforward texts on subjects of personal interest or familiar academic topics while making informed decisions about one’s own reaction to the text. (I.1, I2, S.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.3.9', 'Skim and scan reference materials, in print or online, in order to identify information that might be of practical use for one’s own research and academic needs', 'BGU', 'I.EFL.5.11.1. Learners can identify and apply a range of reading strategies in order to make texts meaningful and to select information within a text that might be of practical use for one’s own academic needs. (I.1, I.2, I.4, S.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.1', 'Critically evaluate information from references, including those found on the web, and recommend print and digital sources to other learners', 'BGU', 'I.EFL.5.14.1. Learners can identify, critically evaluate and recommend a variety of potential resources and references, including digital tools that support collaboration and productivity, for educational and academic use. (I.1, I.2, S.3, S.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.2', 'Identify a variety of types and formats of potential resources and the value, purpose and audience of each for use in the educational domain. (Example: audio/video, multimedia, website, database, book, thesaurus, scholarly/popular, current/historical, etc.)', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.3', 'Apply new and prior knowledge in order to plan and create texts and determine if the new knowledge adds value to or contradicts prior information', 'BGU', 'I.EFL.5.15.1 Learners can plan and produce well-constructed informational texts by applying the writing process and while demonstrating an ability to justify one’s position on an argument through carefully selected information and appropriate language, tone, and evidence. (I.2, I.3, I.4, S.3, J.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.4', 'Select and make effective use of a range of digital tools to write, edit, revise and publish written work in a way that supports collaboration, learning and productivity. (Example: image editing, Google Drive, infographic makers, audio and video editing, presentation apps, etc.)', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.5', 'Justify and explain the rationale for a position on an argument, using per-suasive language, tone, evidence and well-developed arguments through essays, editorials, movie and book reviews, position papers and brochures', 'BGU', 'I.EFL.5.15.1 Learners can plan and produce well-constructed informational texts by applying the writing process and while demonstrating an ability to justify one’s position on an argument through carefully selected information and appropriate language, tone, and evidence. (I.2, I.3, I.4, S.3, J.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.6', 'Produce emails and blog posts describing personal experiences and feelings', 'BGU', 'I.EFL.5.13.1. Learners can produce emails, blog posts, and other written texts using an effective voice and a variety of appropriate writing styles and conventions. (I.3, S.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.7', 'Use the process of prewriting, drafting, revising, peer editing and proofreading (i.e., the writing process) to produce well-constructed informational texts', 'BGU', 'I.EFL.5.15.1 Learners can plan and produce well-constructed informational texts by applying the writing process and while demonstrating an ability to justify one’s position on an argument through carefully selected information and appropriate language, tone, and evidence. (I.2, I.3, I.4, S.3, J.1)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.8', 'Create an effective voice, using a variety of writing styles appropriate to different audiences, purposes and set tings, and adjust these styles as necessary', 'BGU', 'I.EFL.5.13.1. Learners can produce emails, blog posts, and other written texts using an effective voice and a variety of appropriate writing styles and conventions. (I.3, S.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.4.9', 'Use a variety of oral, print and electronic forms for writing to others or for writing for self, applying the conventions of social writing. (Example: notes, invitations, emails, blog entries and comments, notes to self, etc.)', 'BGU', 'I.EFL.5.13.1. Learners can produce emails, blog posts, and other written texts using an effective voice and a variety of appropriate writing styles and conventions. (I.3, S.3, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.1', 'Compare and present personal and formal responses to and interpretations of published literary texts and the works of peers, referring to details and features of the text. (Example: text structure, plot, ideas, events, vocabulary, etc.)', 'BGU', 'I.EFL.5.16.1. Learners can respond to and interpret literary texts, including original stories written by peers, referring to details and literary elements of the text. (S.1, S.4, J.2)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.10', 'Evaluate and recommend a literary text (written, oral, online, in video or in print) or a favorite activity to a peer', 'BGU', 'I.EFL.5.18.1. Learners can use a variety of criteria for evaluating and recommending literary texts to others and recognize how chosen criteria affects evaluation. (S.1, S.4, J.2, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.2', 'Make predictions, inferences and deductions to demonstrate different levels of meaning of literary texts presented orally or in digital form, including literal and implied meanings. (Example: summarizing, explaining and identifying, word choice, symbols, points of view, etc.)', 'BGU', 'Learners can demonstrate and convey different levels of meaning in literary texts, interpreting implicit and explicit messages and responding in a variety of ways. (I.3, I.4, J.3) (Ref.I.EFL.5.17.1.) (I.3,I.4,J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.4', 'Read aloud with confidence, accuracy, fluency and expression to demonstrate understanding and to convey an interpretation of meaning', 'BGU', 'Learners can demonstrate and convey different levels of meaning in literary texts, interpreting implicit and explicit messages and responding in a variety of ways. (I.3, I.4, J.3) (Ref.I.EFL.5.17.1.) (I.3,I.4,J.3)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.5', 'Create original, imaginative stories using appropriate vocabulary and elements of the literature learners have read or heard', 'BGU', null),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.6', 'Evaluate one’s own and others’ work, individually and collaboratively, on the basis of a variety of criteria, and recognize how chosen criteria affect evaluation. (Examples of criteria: clarity of ideas, use of English grammar and vocabulary, register, originality, visual presentation, etc.)', 'BGU', 'I.EFL.5.18.1. Learners can use a variety of criteria for evaluating and recommending literary texts to others and recognize how chosen criteria affects evaluation. (S.1, S.4, J.2, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.7', 'Collaboratively produce criteria for evaluating literary texts and the effectiveness of group work', 'BGU', 'I.EFL.5.19.1 Learners can engage in collaborative activities through a variety of student groupings in order to 4solve problems and reflect on literary texts and produce criteria for evaluating the effectiveness of the group. (I.1, I.2, S.2, S.3, S.4, J.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.8', 'Contribute to team projects to produce original works and solve problems while effectively negotiating and managing interactions to accomplish social and classroom tasks', 'BGU', 'I.EFL.5.19.1 Learners can engage in collaborative activities through a variety of student groupings in order to 4solve problems and reflect on literary texts and produce criteria for evaluating the effectiveness of the group. (I.1, I.2, S.2, S.3, S.4, J.3, J.4)'),
  ((select id from asignaturas where codigo = 'EXT'), 'EFL.5.5.9', 'Engage in collaborative activities through a variety of student groupings to share, reflect on, express and interpret opinions and evaluations of a range of literary texts. (Example: small groups, cooperative learning groups, literature circles, process writing groups, etc.)', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.1', 'Determinar la posición y el desplazamiento de un objeto (considerado puntual) que se mueve, a lo largo de una trayectoria rectilínea, en un sistema de referencia establecida y sistematizar información relacionada al cambio de posición en función del tiempo, como resultado de la observación de movimiento de un objeto y el empleo de tablas y gráficas. CN', 'BGU', 'I.CN.F.5.1.1. Determina magnitudes cinemáticas escalares como: posición, desplazamiento, rapidez en el MRU, a partir de tablas y gráficas. (I.1., I2.) I.CN.F.5.1.2. Obtiene a base de tablas y gráficos las magnitudes cinemáticas del MRUV como: posición, velocidad, velocidad media e instantánea, aceleración, aceleración media e instantánea y desplazamiento. (I.1., I2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.10', 'Establecer la importancia de la persuasión como base de la deliberación en el ejercicio de la ciudadanía. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.11', 'Aplicar el método socrático y el diálogo estructurado en función de la construcción de un pensamiento creativo. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.12', 'Analizar gráficamente que, en el caso particular de que la trayectoria sea un círculo, la aceleración normal se llama aceleración central (centrípeta) y determinar que en el movimiento circular solo se necesita el ángulo (medido en radianes) entre la posición del objeto y una dirección de referencia, mediante el análisis gráfico de un punto situado en un objeto que gira alrededor de un eje. CN', 'BGU', 'I.CN.F.5.3.1 Determina las magnitudes cinemáticas del movimiento circular uniforme y explica las características del mismo considerando las aceleraciones normal y centrípeta, a base de un objeto que gira en torno a un eje. (I.1., I.2.) I.CN.F.5.3.2 Resuelve problemas de aplicación de movimiento circular uniformemente variado y establece analogías entre el MRU y MCU. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.13', 'Diferenciar, mediante el análisis de gráficos el movimiento circular uniforme (MCU) del movimiento circular uniformemente variado (MCUV), en función de la comprensión de las características y relaciones de las cuatro magnitudes de la cinemática del movimiento circular (posición angular, velocidad angular, aceleración angular y el tiempo). CN', 'BGU', 'I.CN.F.5.3.1 Determina las magnitudes cinemáticas del movimiento circular uniforme y explica las características del mismo considerando las aceleraciones normal y centrípeta, a base de un objeto que gira en torno a un eje. (I.1., I.2.) I.CN.F.5.3.2 Resuelve problemas de aplicación de movimiento circular uniformemente variado y establece analogías entre el MRU y MCU. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.14', 'Evaluar críticamente las políticas nacionales e internacionales sobre movilidad humana, proponiendo acciones que promuevan la protección de los derechos de migrantes y refugiados, y la integración sostenible de las personas en movilidad en las comunidades receptoras a nivel local, regional o global. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.15', 'Resolver problemas de aplicación donde se relacionen las magnitudes angulares y las lineales', 'BGU', 'I.CN.F.5.3.1 Determina las magnitudes cinemáticas del movimiento circular uniforme y explica las características del mismo considerando las aceleraciones normal y centrípeta, a base de un objeto que gira en torno a un eje. (I.1., I.2.) I.CN.F.5.3.2 Resuelve problemas de aplicación de movimiento circular uniformemente variado y establece analogías entre el MRU y MCU. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.16', 'Indagar los estudios de Aristóteles, Galileo y Newton, para comparar sus experiencias frente a las razones por las que se mueven los objetos, y despejar ideas preconcebidas sobre este fenómeno, con la finalidad de conceptualizar la primera ley de Newton (ley de la inercia) y determinar por medio de la experimentación que no se produce aceleración cuando las fuerzas están en equilibrio, por lo que un objeto continúa moviéndose con rapidez constante o permanece en reposo (primera ley de Newton o principio de inercia de Galileo)', 'BGU', 'I.CN.F.5.4.1. Elabora diagramas de cuerpo libre, resuelve problemas y reconoce sistemas inerciales y no inerciales, aplicando las leyes de Newton, cuando el objeto es mucho mayor que una partícula elemental y se mueve a velocidades inferiores a la de la luz. (I.2., I.4.) Determina el teorema del impulso y la cantidad de movimiento, el principio de conservación de la cantidad de movimiento lineal y el centro de masa para un sistema simple de dos cuerpos. (Ref.I.CN. F.5.4.2 ). (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.17', 'Explicar la segunda ley de Newton, mediante la relación entre las magnitudes: aceleración y fuerza que actúan sobre un objeto y su masa, mediante experimentaciones formales o no formales. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.18', 'Explicar la tercera ley de Newton en aplicaciones reales. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.19', 'Reconocer sistemas inerciales y no inerciales a través de la observación de videos y análisis de situaciones cotidianas y elaborar diagramas de cuerpo libre para conceptualizar las leyes de Newton, resolver problemas de aplicación. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.20', 'Reconocer que la fuerza es una magnitud de naturaleza vectorial, mediante la explicación gráfica de situaciones reales para resolver problemas donde se observen objetos en equilibrio u objetos acelerados. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.22', 'Reconocer que la velocidad es una información insuficiente y que lo fundamental es la vinculación de la masa del objeto con su velocidad a través de la cantidad de movimiento lineal, para comprender la ley de conservación de la cantidad de movimiento y demostrar analíticamente que el impulso de la fuerza que actúa sobre un objeto es igual a la variación de la cantidad de movimiento de ese objeto. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.23', 'Explicar que la fuerza es la variación de momento lineal en el transcurso del tiempo, mediante ejemplos reales, y determinar mediante la aplicación del teorema del impulso, la cantidad de movimiento y, por medio de la tercera ley de Newton ver que, para un sistema aislado de dos cuerpos, no existe cambio en el tiempo de la cantidad de movimiento total del sistema', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.25', 'Explicar que la intensidad del campo gravitatorio de un planeta determina la fuerza del peso de un objeto de masa (m), para establecer que el peso puede variar, pero la masa es la misma. CN', 'BGU', 'I.CN.F.5.5.1 Determina el peso y analiza el lanzamiento vertical y caída libre (considerando y sin considerar la resistencia del aire) de un objeto, en función de la intensidad del campo gravitatorio. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.26', 'Determinar que el lanzamiento vertical y la caída libre son casos concretos del movimiento unidimensional con aceleración constante (g), mediante ejemplificaciones y utilizar las ecuaciones del movimiento vertical en la solución de problemas. CN', 'BGU', 'I.CN.F.5.5.1 Determina el peso y analiza el lanzamiento vertical y caída libre (considerando y sin considerar la resistencia del aire) de un objeto, en función de la intensidad del campo gravitatorio. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.27', 'Explicar el fenómeno de la aceleración cuando un cuerpo que cae libremente alcanza su rapidez terminal, mediante el análisis del rozamiento con el aire', 'BGU', 'I.CN.F.5.5.1 Determina el peso y analiza el lanzamiento vertical y caída libre (considerando y sin considerar la resistencia del aire) de un objeto, en función de la intensidad del campo gravitatorio. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.29', 'Describir el movimiento de proyectiles en la superficie de la Tierra, mediante la determinación de las coordenadas horizontal y vertical del objeto para cada instante del vuelo y de las relaciones entre sus magnitudes (velocidad, aceleración, tiempo); determinar el alcance horizontal y la altura máxima alcanzada por un proyectil y su relación con el ángulo de lanzamiento, a través del análisis del tiempo que se demora un objeto en seguir la trayectoria, que es el mismo que emplean sus proyecciones en los ejes', 'BGU', 'I.CN.F.5.6.1. Analiza la velocidad, ángulo de lanzamiento, aceleración, alcance, altura máxima, tiempo de vuelo, aceleración normal y centrípeta en el movimiento de proyectiles, en función de la naturaleza vectorial de la segunda ley de Newton. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.3', 'Obtener la velocidad instantánea empleando el gráfico posición en función del tiempo, y conceptualizar la aceleración media e instantánea, mediante el análisis de las gráficas velocidad en función del tiempo. CN', 'BGU', 'I.CN.F.5.1.1. Determina magnitudes cinemáticas escalares como: posición, desplazamiento, rapidez en el MRU, a partir de tablas y gráficas. (I.1., I2.) I.CN.F.5.1.2. Obtiene a base de tablas y gráficos las magnitudes cinemáticas del MRUV como: posición, velocidad, velocidad media e instantánea, aceleración, aceleración media e instantánea y desplazamiento. (I.1., I2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.30', 'Observar en objetos y fenómenos las fuerzas de compresión o de tracción que causan la deformación de los objetos e inferir su importancia en su vida cotidiana', 'BGU', 'I.CN.F.5.7.1 Argumenta desde la experimentación y la observación de fenómenos la ley de Hooke (fuerza que ejerce un resorte es proporcional a la deformación que experimenta), estableciendo su modelo matemático y su importancia para la vida cotidiana. (I.2., S.4.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.31', 'Determinar que la fuerza que ejerce un resorte es proporcional a la deformación que experimenta y está dirigida hacia la posición de equilibrio (ley de Hooke), mediante prácticas experimentales y el análisis de su modelo matemático y de la característica de cada resorte', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.32', 'Explicar que el movimiento circular uniforme requiere la aplicación de una fuerza constante dirigida hacia el centro del círculo, mediante la demostración analítica y/o experimental. CN', 'BGU', 'Argumenta, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción), a partir de las fuerzas involucradas en MCU (la fuerza centrífuga es una fuerza ficticia). (Ref.I.CN. F.5.8.1.). (I.2.) Determina, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción). (Ref.I.CN. F.5.8.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.34', 'Deducir las expresiones cinemáticas a través del análisis geométrico del movimiento armónico simple (MAS) y del uso de las funciones seno o coseno (en dependencia del eje escogido), y que se puede equiparar la amplitud A y la frecuencia angular w del MAS con el radio y la velocidad angular del MCU. CN', 'BGU', 'Argumenta, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción), a partir de las fuerzas involucradas en MCU (la fuerza centrífuga es una fuerza ficticia). (Ref.I.CN. F.5.8.1.). (I.2.) Determina, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción). (Ref.I.CN. F.5.8.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.35', 'Determinar experimentalmente que un objeto sujeto a un resorte realiza un movimiento periódico (llamado movimiento armónico simple) cuando se estira o se comprime, generando una fuerza elástica dirigida hacia la posición de equilibrio y proporcional a la deformación', 'BGU', 'Argumenta, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción), a partir de las fuerzas involucradas en MCU (la fuerza centrífuga es una fuerza ficticia). (Ref.I.CN. F.5.8.1.). (I.2.) Determina, experimentalmente, las magnitudes que intervienen en el MAS cuando un resorte se comprime o estira (sin considerar las fuerzas de fricción). (Ref.I.CN. F.5.8.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.38', 'Explicar que se detecta el origen de la carga eléctrica, partiendo de la comprensión de que esta reside en los constituyentes del átomo (electrones o protones) y que solo se detecta su presencia por los efectos entre ellas, comprobar la existencia de solo dos tipos de carga eléctrica a partir de mecanismos que permiten la identificación de fuerzas de atracción y repulsión entre objetos electrificados, en situaciones cotidianas y experimentar el proceso de carga por polarización electrostática, con materiales de uso cotidiano', 'BGU', 'CN.F.5.9.1. Argumenta, mediante la experimentación y análisis del modelo de gas de electrones, el origen atómico de la carga eléctrica, el tipo de materiales según su capacidad de conducción de carga, la relación de masa entre protón y electrón e identifica aparatos de uso cotidiano que separan cargas eléctricas. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.4', 'Elaborar gráficos de velocidad versus tiempo, a partir de los gráficos posición versus tiempo; y determinar el desplazamiento a partir del gráfico velocidad vs tiempo', 'BGU', 'I.CN.F.5.1.1. Determina magnitudes cinemáticas escalares como: posición, desplazamiento, rapidez en el MRU, a partir de tablas y gráficas. (I.1., I2.) I.CN.F.5.1.2. Obtiene a base de tablas y gráficos las magnitudes cinemáticas del MRUV como: posición, velocidad, velocidad media e instantánea, aceleración, aceleración media e instantánea y desplazamiento. (I.1., I2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.41', 'Analizar y explicar los aparatos o dispositivos que tienen la característica de separar cargas eléctricas, mediante la descripción de objetos de uso cotidiano. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.42', 'Explicar las propiedades de conductividad eléctrica de un metal en función del modelo del gas de electrones', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.43', 'Conceptualizar la ley de Coulomb en función de cuantificar con qué fuerza se atraen o se repelen las cargas eléctricas y determinar que esta fuerza electrostática también es de naturaleza vectorial. CN', 'BGU', 'I.CN.F.5.10.1. Resuelve problemas de aplicación de la ley de Coulomb, usando el principio de superposición y presencia de un campo eléctrico alrededor de una carga puntual. (I.2.) I.CN.F.5.10.2. Argumenta los efectos de las líneas de campo en demostraciones con material concreto, la diferencia de potencial eléctrico (considerando el trabajo realizado al mover cargas dentro de un campo eléctrico) y la corriente eléctrica (en cargas que se mueven a través de superficies), estableciendo las transformaciones de energía que pueden darse en un circuito alimentado por una batería eléctrica. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.45', 'Explicar que la presencia de un campo eléctrico alrededor de una carga puntual permite comprender la acción de la fuerza a distancia, la acción a distancia entre cargas a través de la conceptualización de campo eléctrico y la visualización de los efectos de las líneas de campo en demostraciones con material concreto, y determinar la fuerza que experimenta una carga dentro de un campo eléctrico, mediante la resolución de ejercicios y problemas de aplicación. CN', 'BGU', 'I.CN.F.5.10.1. Resuelve problemas de aplicación de la ley de Coulomb, usando el principio de superposición y presencia de un campo eléctrico alrededor de una carga puntual. (I.2.) I.CN.F.5.10.2. Argumenta los efectos de las líneas de campo en demostraciones con material concreto, la diferencia de potencial eléctrico (considerando el trabajo realizado al mover cargas dentro de un campo eléctrico) y la corriente eléctrica (en cargas que se mueven a través de superficies), estableciendo las transformaciones de energía que pueden darse en un circuito alimentado por una batería eléctrica. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.46', 'Establecer que el trabajo efectuado por un agente externo al mover una carga de un punto a otro dentro del campo eléctrico se almacena como energía potencial eléctrica e identificar el agente externo que genera diferencia de potencial eléctrico, el mismo que es capaz de generar trabajo al mover una carga positiva unitaria de un punto a otro dentro de un campo eléctrico', 'BGU', 'I.CN.F.5.10.1. Resuelve problemas de aplicación de la ley de Coulomb, usando el principio de superposición y presencia de un campo eléctrico alrededor de una carga puntual. (I.2.) I.CN.F.5.10.2. Argumenta los efectos de las líneas de campo en demostraciones con material concreto, la diferencia de potencial eléctrico (considerando el trabajo realizado al mover cargas dentro de un campo eléctrico) y la corriente eléctrica (en cargas que se mueven a través de superficies), estableciendo las transformaciones de energía que pueden darse en un circuito alimentado por una batería eléctrica. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.49', 'Describir la relación entre diferencia de potencial (voltaje), corriente y resistencia eléctrica, la ley de Ohm, mediante la comprobación de que la corriente en un conductor es proporcional al voltaje aplicado (donde R es la constante de proporcionalidad). CN', 'BGU', 'Demuestra mediante la experimentación el voltaje, la intensidad de corriente eléctrica, la resistencia y la potencia (comprendiendo el calentamiento de Joule), en circuitos sencillos alimentados por baterías o fuentes de corriente continua. (Ref. I.CN.F.5.11.1.) (I.1.,I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.51', 'Comprobar la ley de Ohm en circuitos sencillos a partir de la experimentación, analizar el funcionamiento de un circuito eléctrico sencillo y su simbología mediante la identificación de sus elementos constitutivos y la aplicación de dos de las grandes leyes de conservación (de la carga y de la energía) y explicar el calentamiento de Joule y su significado mediante la determinación de la potencia disipada en un circuito básico', 'BGU', 'Demuestra mediante la experimentación el voltaje, la intensidad de corriente eléctrica, la resistencia y la potencia (comprendiendo el calentamiento de Joule), en circuitos sencillos alimentados por baterías o fuentes de corriente continua. (Ref. I.CN.F.5.11.1.) (I.1.,I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.54', 'Reconocer la naturaleza vectorial de un campo magnético, a través del análisis de sus características, determinar la intensidad del campo magnético en la solución de problemas de aplicación práctica, establecer la fuerza que ejerce el campo magnético uniforme sobre una partícula cargada que se mueve en su interior a partir de su expresión matemática. CN', 'BGU', 'Reconoce que las únicas fuentes de campos magnéticos son los materiales magnéticos y las corrientes eléctricas. (Ref.I.CN.F.5.12.1.)(I.2.) Explica el funcionamiento de un motor eléctrico, mediante la acción de fuerzas magnéticas sobre un objeto que lleva corriente ubicada en el interior de un campo magnético uniforme, la magnitud y dirección del campo magnético próximo a un conductor rectilíneo largo y la ley de Ampère. (Ref. I.CN.F.5.12.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.55', 'Explicar el funcionamiento del motor eléctrico por medio de la acción de fuerzas magnéticas sobre un objeto que lleva corriente ubicada en el interior de un campo magnético uniforme. CN', 'BGU', 'Reconoce que las únicas fuentes de campos magnéticos son los materiales magnéticos y las corrientes eléctricas. (Ref.I.CN.F.5.12.1.)(I.2.) Explica el funcionamiento de un motor eléctrico, mediante la acción de fuerzas magnéticas sobre un objeto que lleva corriente ubicada en el interior de un campo magnético uniforme, la magnitud y dirección del campo magnético próximo a un conductor rectilíneo largo y la ley de Ampère. (Ref. I.CN.F.5.12.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.57', 'Conceptualizar la ley de Ampère, mediante la identificación de que la circulación de un campo magnético en un camino cerrado es directamente proporcional a la corriente eléctrica encerrada por el camino', 'BGU', 'Reconoce que las únicas fuentes de campos magnéticos son los materiales magnéticos y las corrientes eléctricas. (Ref.I.CN.F.5.12.1.)(I.2.) Explica el funcionamiento de un motor eléctrico, mediante la acción de fuerzas magnéticas sobre un objeto que lleva corriente ubicada en el interior de un campo magnético uniforme, la magnitud y dirección del campo magnético próximo a un conductor rectilíneo largo y la ley de Ampère. (Ref. I.CN.F.5.12.2.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.6', 'Discutir los desafíos planteados por Hipatia como pensadora y como mujer en la perspectiva de comprender actuales formas de intolerancia e irracionalidad. CS', 'BGU', 'I.CS.F.5.2.1. Compara las desigualdades de la democracia griega con la actual, a partir del análisis del caso de intolerancia e irracionalidad que sufrió la pensadora Hipatia, representante de la escuela neoplatónica, y de la carencia de la persuasión y la deliberación en el ejercicio de la ciudadanía a través de conceptos fundamentales sobre la comunidad, el quehacer y formas políticas. (J.1., J.4., S.1.) I.CS.F.5.2.2. Examina la importancia del método socrático y el diálogo racional y estructurado en la experiencia comunicativa del ser humano como “animal político”, en función de dilucidar las relaciones de poder que legitima una u otra posición filosófica. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.7', 'Establecer las diferencias entre vector posición y vector desplazamiento, y analizar gráficas que representen la trayectoria en dos dimensiones de un objeto, observando la ubicación del vector posición y vector desplazamiento para diferentes instantes. CN', 'BGU', 'Obtiene magnitudes cinemáticas del MRUV con un enfoque vectorial, como: posición, velocidad, velocidad media e instantánea, y desplazamiento a base de representaciones gráficas de un objeto que se mueve en dos dimensiones. (Ref.I.CN. F.5.2.1.). (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.8', 'Describir y categorizar el alcance de la idea del ser humano como “animal político” en función de su necesidad de vivir en sociedad', 'BGU', 'I.CS.F.5.2.1. Compara las desigualdades de la democracia griega con la actual, a partir del análisis del caso de intolerancia e irracionalidad que sufrió la pensadora Hipatia, representante de la escuela neoplatónica, y de la carencia de la persuasión y la deliberación en el ejercicio de la ciudadanía a través de conceptos fundamentales sobre la comunidad, el quehacer y formas políticas. (J.1., J.4., S.1.) I.CS.F.5.2.2. Examina la importancia del método socrático y el diálogo racional y estructurado en la experiencia comunicativa del ser humano como “animal político”, en función de dilucidar las relaciones de poder que legitima una u otra posición filosófica. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.1.9', 'Construir, a partir del gráfico posición versus tiempo, el vector velocidad instantánea evaluado en el instante inicial, considerando los vectores, posiciones y desplazamiento para dos instantes diferentes, inicial y final, haciendo que el instante final se aproxime al inicial tanto como se desee (pero que nunca son iguales), y reconocer que la dirección del vector velocidad instantánea se encuentra en la dirección de la línea tangente a la trayectoria en el instante inicial', 'BGU', 'Obtiene magnitudes cinemáticas del MRUV con un enfoque vectorial, como: posición, velocidad, velocidad media e instantánea, y desplazamiento a base de representaciones gráficas de un objeto que se mueve en dos dimensiones. (Ref.I.CN. F.5.2.1.). (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.1', 'Definir el trabajo mecánico a partir del análisis de la acción de una fuerza constante aplicada a un objeto que se desplaza en forma rectilínea, considerando solo el componente de la fuerza en la dirección del desplazamiento. CN', 'BGU', 'I.CN.F.5.13.1. Determina, mediante ejercicios de aplicación, el trabajo mecánico con fuerzas constantes, energía mecánica, conservación de energía, potencia y trabajo negativo producido por las fuerzas de fricción al mover un objeto a lo largo de cualquier trayectoria cerrada. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.10', 'Reconocer mediante la experimentación de motores de combustión interna y eléctricos que, en sistemas mecánicos, las transferencias y transformaciones de la energía siempre causan pérdida de calor hacia el ambiente, reduciendo la energía utilizable, considerando que un sistema mecánico no puede ser ciento por ciento eficiente. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.11', 'Experimentar y determinar que la mayoría de los procesos tienden a disminuir el orden de un sistema conforme transcurre el tiempo', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.12', 'Establecer semejanzas y diferencias entre las formas de pensamiento cotidiano y el ejercicio del pensamiento filosófico y científico, en función de su valoración diferenciada. CS', 'BGU', 'I.CS.F.5.1.1. Analiza el origen del pensamiento filosófico como crítica al pensamiento mítico, como la búsqueda del orden y la armonía, y como esfuerzo para explicar los fenómenos sociales y naturales, a partir de la reflexión en torno a problemas concretos, y la elaboración de preguntas complejas en función de ensayar respuestas significativas. (I.2.) I.CS.F.5.1.2. Analiza las contribuciones del pensamiento filosófico en las diversas producciones del pensamiento humano en contraste con otras disciplinas, reconociendo la tendencia filosófica en cuanto a lo absoluto, hechos factuales y pensamiento cotidiano. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.13', 'Distinguir las características del ensayo latinoamericano y del tratado europeo en textos representativos. CS', 'BGU', 'I.CS.F.5.5.1. Compara las características del pensamiento filosófico occidental y latinoamericano, con sus nuevas concepciones, identificando sus preocupaciones esenciales (“yo” – “nosotros”; “objetividad” “subjetividad”; “libertad” – “liberación”), su contexto histórico, su identidad, cultura y las características de sus productos intelectuales específicos (el ensayo y el tratado), discutiendo desde el método socrático el Sumak Kawsay como proyecto utópico posible en la construcción del “ser” latinoamericano. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.14', 'Contrastar las perspectivas de objetividad y subjetividad presentes en el tratado europeo y en el ensayo latinoamericano, mediante el análisis del discurso, su descomposición en elementos y su posterior síntesis. S', 'BGU', 'I.CS.F.5.5.1. Compara las características del pensamiento filosófico occidental y latinoamericano, con sus nuevas concepciones, identificando sus preocupaciones esenciales (“yo” – “nosotros”; “objetividad” “subjetividad”; “libertad” – “liberación”), su contexto histórico, su identidad, cultura y las características de sus productos intelectuales específicos (el ensayo y el tratado), discutiendo desde el método socrático el Sumak Kawsay como proyecto utópico posible en la construcción del “ser” latinoamericano. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.15', 'Desarrollar alguna reflexión filosófica que evidencie los rasgos distintivos entre ensayo y tratado. CS', 'BGU', 'I.CS.F.5.5.1. Compara las características del pensamiento filosófico occidental y latinoamericano, con sus nuevas concepciones, identificando sus preocupaciones esenciales (“yo” – “nosotros”; “objetividad” “subjetividad”; “libertad” – “liberación”), su contexto histórico, su identidad, cultura y las características de sus productos intelectuales específicos (el ensayo y el tratado), discutiendo desde el método socrático el Sumak Kawsay como proyecto utópico posible en la construcción del “ser” latinoamericano. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.16', 'Identificar tesis centrales y secundarias en un discurso filosófico corto', 'BGU', 'I.CS.F.5.4.1. Comprende y aplica las estructuras y principios de la argumentación lógica y lógica simbólica, evitando falacias, paradojas y contradicciones, estableciendo las tesis centrales y secundarias en la construcción de un discurso coherente y riguroso. (I.1.) I.CS.F.5.4.2. Diferencia las falacias de las paradojas, comprendiendo y aplicando los principios de la argumentación y deliberación, en el análisis de textos académicos y de prensa. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.17', 'Identificar características de la identidad del “ser” latinoamericano en diversas expresiones artísticas (pintura, escultura, poesía, arquitectura, novela, ensayo literario) para elaborar un discurso y repensar su “ethos” a inicios del siglo XXI. CS', 'BGU', 'I.CS.F.5.5.1. Compara las características del pensamiento filosófico occidental y latinoamericano, con sus nuevas concepciones, identificando sus preocupaciones esenciales (“yo” – “nosotros”; “objetividad” “subjetividad”; “libertad” – “liberación”), su contexto histórico, su identidad, cultura y las características de sus productos intelectuales específicos (el ensayo y el tratado), discutiendo desde el método socrático el Sumak Kawsay como proyecto utópico posible en la construcción del “ser” latinoamericano. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.18', 'Analizar las nuevas concepciones de la filosofía latinoamericana por medio de ejercicios orales y escritos. CS', 'BGU', 'I.CS.F.5.5.1. Compara las características del pensamiento filosófico occidental y latinoamericano, con sus nuevas concepciones, identificando sus preocupaciones esenciales (“yo” – “nosotros”; “objetividad” “subjetividad”; “libertad” – “liberación”), su contexto histórico, su identidad, cultura y las características de sus productos intelectuales específicos (el ensayo y el tratado), discutiendo desde el método socrático el Sumak Kawsay como proyecto utópico posible en la construcción del “ser” latinoamericano. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.2', 'Demostrar analíticamente que la variación de la energía mecánica representa el trabajo realizado por un objeto, utilizando la segunda ley de Newton y las leyes de la cinemática y la conservación de la energía, a través de la resolución de problemas que involucren el análisis de sistemas conservativos donde solo fuerzas conservativas efectúan trabajo. CN', 'BGU', 'I.CN.F.5.13.1. Determina, mediante ejercicios de aplicación, el trabajo mecánico con fuerzas constantes, energía mecánica, conservación de energía, potencia y trabajo negativo producido por las fuerzas de fricción al mover un objeto a lo largo de cualquier trayectoria cerrada. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.3', 'Analizar las estructuras y los principios generales de la argumentación lógica (lógica aristotélica, silogismos) para cultivar un pensamiento coherente y riguroso. CS', 'BGU', 'I.CS.F.5.4.1. Comprende y aplica las estructuras y principios de la argumentación lógica y lógica simbólica, evitando falacias, paradojas y contradicciones, estableciendo las tesis centrales y secundarias en la construcción de un discurso coherente y riguroso. (I.1.) I.CS.F.5.4.2. Diferencia las falacias de las paradojas, comprendiendo y aplicando los principios de la argumentación y deliberación, en el análisis de textos académicos y de prensa. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.4', 'Determinar el concepto de potencia mediante de la comprensión del ritmo temporal con que ingresa o se retira energía de un sistema', 'BGU', 'I.CN.F.5.13.1. Determina, mediante ejercicios de aplicación, el trabajo mecánico con fuerzas constantes, energía mecánica, conservación de energía, potencia y trabajo negativo producido por las fuerzas de fricción al mover un objeto a lo largo de cualquier trayectoria cerrada. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.5', 'Analizar la presencia de las principales falacias en textos académicos y de la prensa nacional e internacional. CS', 'BGU', 'I.CS.F.5.4.1. Comprende y aplica las estructuras y principios de la argumentación lógica y lógica simbólica, evitando falacias, paradojas y contradicciones, estableciendo las tesis centrales y secundarias en la construcción de un discurso coherente y riguroso. (I.1.) I.CS.F.5.4.2. Diferencia las falacias de las paradojas, comprendiendo y aplicando los principios de la argumentación y deliberación, en el análisis de textos académicos y de prensa. (J.3.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.7', 'Analizar que la variación de la temperatura de una sustancia que no cambia de estado es proporcional a la cantidad de energía añadida o retirada de la sustancia y que la constante de proporcionalidad representa el recíproco de la capacidad calorífica de la sustancia. CN', 'BGU', 'I.CN.F.5.14.1. Analiza la temperatura como energía cinética promedio de sus partículas y experimenta la ley cero de la termodinámica (usando conceptos de calor especifico, cambio de estado, calor latente y temperatura de equilibrio), la transferencia de calor (por conducción, convección y radiación), el trabajo mecánico producido por la energía térmica de un sistema y las pérdidas de energía en forma de calor hacia el ambiente y disminución del orden , que tienen lugar durante los procesos de transformación de energía. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.8', 'Explicar mediante la experimentación el equilibrio térmico usando los conceptos de calor específico, cambio de estado, calor latente, temperatura de equilibrio, en situaciones cotidianas. CN', 'BGU', 'I.CN.F.5.14.1. Analiza la temperatura como energía cinética promedio de sus partículas y experimenta la ley cero de la termodinámica (usando conceptos de calor especifico, cambio de estado, calor latente y temperatura de equilibrio), la transferencia de calor (por conducción, convección y radiación), el trabajo mecánico producido por la energía térmica de un sistema y las pérdidas de energía en forma de calor hacia el ambiente y disminución del orden , que tienen lugar durante los procesos de transformación de energía. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.2.9', 'Reconocer que un sistema con energía térmica tiene la capacidad de realizar trabajo mecánico deduciendo que, cuando el trabajo termina, cambia la energía interna del sistema, a partir de la experimentación (máquinas térmicas)', 'BGU', 'I.CN.F.5.14.1. Analiza la temperatura como energía cinética promedio de sus partículas y experimenta la ley cero de la termodinámica (usando conceptos de calor especifico, cambio de estado, calor latente y temperatura de equilibrio), la transferencia de calor (por conducción, convección y radiación), el trabajo mecánico producido por la energía térmica de un sistema y las pérdidas de energía en forma de calor hacia el ambiente y disminución del orden , que tienen lugar durante los procesos de transformación de energía. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.1', 'Describir las relaciones de los elementos de la onda: amplitud, periodo y frecuencia, mediante su representación en diagramas que muestren el estado de las perturbaciones para diferentes instantes. CN', 'BGU', 'Describe con base en un “modelo de ondas mecánicas” los elementos de una onda, su clasificación en función del modelo elástico y dirección de propagación y a base de un “modelo de rayos “los fenómenos de reflexión, refracción y la formación de imágenes en lentes y espejos, que cuando un rayo de luz atraviesa un prisma, esta se descompone en colores que van desde el infrarrojo hasta el ultravioleta y el efecto Doppler. (Ref.I.CN. F.5.15.1 ). (I.2.) I.CN.F.5.15.2. Establece la dualidad onda partícula de la luz y las aplicaciones de las ondas en la transmisión de energía e información en ondas en los equipos de uso diario. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.10', 'Discutir las propuestas de las construcciones intelectuales de los pueblos ancestrales como proyecto utópico de otro mundo posible, en función de una nueva sociedad', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.2', 'Reconocer que las ondas se propagan con una velocidad que depende de las propiedades físicas del medio de propagación, en función de determinar que esta velocidad, en forma cinemática, se expresa como el producto de frecuencia por longitud de onda. CN', 'BGU', 'Describe con base en un “modelo de ondas mecánicas” los elementos de una onda, su clasificación en función del modelo elástico y dirección de propagación y a base de un “modelo de rayos “los fenómenos de reflexión, refracción y la formación de imágenes en lentes y espejos, que cuando un rayo de luz atraviesa un prisma, esta se descompone en colores que van desde el infrarrojo hasta el ultravioleta y el efecto Doppler. (Ref.I.CN. F.5.15.1 ). (I.2.) I.CN.F.5.15.2. Establece la dualidad onda partícula de la luz y las aplicaciones de las ondas en la transmisión de energía e información en ondas en los equipos de uso diario. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.3', 'Clasificar los tipos de onda (mecánica o no mecánica) que requieren o no de un medio elástico para su propagación, mediante el análisis de las características y el reconocimiento de que la única onda no mecánica conocida es la onda electromagnética, diferenciando entre ondas longitudinales y transversales con relación a la dirección de oscilación y la dirección de propagación. CN', 'BGU', 'Describe con base en un “modelo de ondas mecánicas” los elementos de una onda, su clasificación en función del modelo elástico y dirección de propagación y a base de un “modelo de rayos “los fenómenos de reflexión, refracción y la formación de imágenes en lentes y espejos, que cuando un rayo de luz atraviesa un prisma, esta se descompone en colores que van desde el infrarrojo hasta el ultravioleta y el efecto Doppler. (Ref.I.CN. F.5.15.1 ). (I.2.) I.CN.F.5.15.2. Establece la dualidad onda partícula de la luz y las aplicaciones de las ondas en la transmisión de energía e información en ondas en los equipos de uso diario. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.4', 'Explicar fenómenos relacionados con la reflexión y refracción, utilizando el modelo de onda mecánica (en resortes o cuerdas) y formación de imágenes en lentes y espejos, utilizando el modelo de rayos', 'BGU', 'Describe con base en un “modelo de ondas mecánicas” los elementos de una onda, su clasificación en función del modelo elástico y dirección de propagación y a base de un “modelo de rayos “los fenómenos de reflexión, refracción y la formación de imágenes en lentes y espejos, que cuando un rayo de luz atraviesa un prisma, esta se descompone en colores que van desde el infrarrojo hasta el ultravioleta y el efecto Doppler. (Ref.I.CN. F.5.15.1 ). (I.2.) I.CN.F.5.15.2. Establece la dualidad onda partícula de la luz y las aplicaciones de las ondas en la transmisión de energía e información en ondas en los equipos de uso diario. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.5', 'Identificar los métodos de comprensión de la realidad en la filosofía latinoamericana a partir sus temas y sus formas de tratamiento de conceptos como libertad y liberación. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.6', 'Explicar que la luz exhibe propiedades de onda pero también de partícula, en función de determinar que no se puede modelar como una onda mecánica porque puede viajar a través del espacio vacío, a una velocidad de aproximadamente 3x108m/s y explicar las diferentes bandas de longitud de onda en el espectro de onda electromagnético, estableciendo relaciones con las aplicaciones en dispositivos de uso cotidiano', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.7', 'Identificar que se generan campos magnéticos en las proximidades de un flujo eléctrico variable y campos eléctricos en las proximidades de flujos magnéticos variables, mediante la descripción de la inducción de Faraday según corresponda. CN', 'BGU', 'I.CN.F.5.16.1. Explica los campos eléctricos generados en las proximidades de flujos magnéticos variables, los campos eléctricos generados en las proximidades de flujos eléctricos variables, el mecanismo de la radiación electromagnética por medio de la observación de videos (mostrando el funcionamiento de aparatos de uso cotidiano), ejemplificando los avances de la mecatrónica al servicio de la sociedad. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.8', 'Analizar el mecanismo de radiación electromagnética, mediante la observación de videos relacionados y la ejemplificación con aparatos de uso cotidiano. CN', 'BGU', 'I.CN.F.5.16.1. Explica los campos eléctricos generados en las proximidades de flujos magnéticos variables, los campos eléctricos generados en las proximidades de flujos eléctricos variables, el mecanismo de la radiación electromagnética por medio de la observación de videos (mostrando el funcionamiento de aparatos de uso cotidiano), ejemplificando los avances de la mecatrónica al servicio de la sociedad. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.3.9', 'Aplicar el método socrático en la reflexión del problema de la “liberación” frente al tópico de la “libertad”, desde diversas perspectivas (historia social y política, ensayos filosóficos). CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.1', 'Discutir las virtudes platónicas y aristotélicas presentes en las acciones humanas y aplicarlas a la sociedad actual. CS', 'BGU', 'I.CS.F.5.6.1. Comprende los fundamentos filosóficos de la ética, las nociones del bien y el mal, las nociones cristianas de la virtud y el pecado y las reflexiones del kantismo y el utilitarismo, mediante el análisis de casos reales del sistema político y la sociedad. (J.1., J.3., I.4.) I.CS.F.5.6.2. Discute las virtudes platónicas y aristotélicas a partir de la reflexión en torno a las corrientes sobre el bien y el mal, destacando la formación de una opinión argumentada en casos de la vida cotidiana. (J.2., I.2., S.1.) I.CS.F.5.6.3. Actúa con respeto hacia los usuarios de medios de transporte público y sostenible, demostrando una conciencia ética y de responsabilidad vial. (J.2., J.3., S.1.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.10', 'Evaluar los significados de estética y belleza en diferentes expresiones, épocas y culturas (arte, artesanía, música, estética personal) por medio de la experiencia personal y la indagación grupal. CS', 'BGU', 'I.CS.F.5.7.1. Discute los significados de estética, belleza, felicidad y placer a partir de las reflexiones de Epicuro y Onfray, relacionándolos con las acciones de la sociedad moderna. (J.4., S4)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.11', 'Comprender la felicidad a partir de la acción y la reflexión humana, tomando en cuenta el análisis de lo público y lo privado', 'BGU', 'I.CS.F.5.7.1. Discute los significados de estética, belleza, felicidad y placer a partir de las reflexiones de Epicuro y Onfray, relacionándolos con las acciones de la sociedad moderna. (J.4., S4)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.12', 'Discutir el tratamiento del placer en Epicuro y Onfray como representantes de distintas épocas históricas, mediante la elaboración de argumentos basados en lecturas seleccionadas. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.13', 'Discutir el tema del placer en la sociedad consumista moderna (lo utilitarista, lo individualista, lo descartable y lo desechable) desde la perspectiva de la ética, la solidaridad y el bienestar colectivo', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.14', 'Proponer estrategias que contemplen acciones de prevención de acoso y violencia sexual en medios de transporte público y sostenible, evitando el uso de estereotipos y prejuicios hacia usuarios', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.2', 'Establecer la ley de gravitación universal de Newton y su explicación del sistema Copernicano y de las leyes de Kepler, para comprender el aporte de la misión geodésica francesa en el Ecuador, con el apoyo profesional de Don Pedro Vicente Maldonado en la confirmación de la ley de gravitación, identificando el problema de acción a distancia que plantea la ley de gravitación newtoniana y su explicación a través del concepto de campo gravitacional', 'BGU', 'Argumenta las tres leyes de Kepler y la ley de gravitación universal de Newton. (Ref.I.CN. F.5.17.1.). (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.3', 'Indagar sobre el cinturón de Kuiper y la nube de Oort, en función de reconocer que en el Sistema Solar y en sus límites existen otros elementos como asteroides, cometas y meteoritos', 'BGU', 'I.CN.F.5.18.1 Explica los límites del Sistema Solar (el cinturón de Kuiper y la nube de Oort), reconociendo que esta zona contiene asteroides, cometas y meteoritos y su ubicación dentro de la Vía Láctea. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.4', 'Comprender la visión occidental y cristiana sobre la virtud y el pecado, mediante el estudio de creencias manifiestas en el medio ecuatoriano. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.6', 'Reflexionar en torno a las corrientes estudiadas sobre el bien y el mal y formar una opinión argumentada sobre su utilidad en la vida cotidiana. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.7', 'Contrastar las posiciones ético-filosóficas del kantismo y el utilitarismo, en función de comprender la construcción social y simbólica de la acción humana. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.8', 'Discutir la relación y pertinencia de la ética en la política y la política en la ética, en función de un ejercicio ciudadano responsable. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.4.9', 'Valorar el sistema político democrático desde una Ética socio-histórica que lo hace posible, mediante el desarrollo de un discurso y alternativas de participación en este sistema. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.1', 'Explicar los fenómenos: radiación de cuerpo negro y efecto fotoeléctrico mediante el modelo de la luz como partícula (el fotón) y que a escala atómica la radiación electromagnética se emite o absorbe en unidades discretas e indivisibles llamadas fotones, cuya energía es proporcional a su frecuencia (constante de Planck). CN', 'BGU', 'Explica los fenómenos de radiación del cuerpo negro, efecto fotoeléctrico, la radiación electromagnética (considerando la luz como partículas), el principio de incertidumbre de Heisenberg. (Ref.I.CN. F.5.19.1.) (I.2) Argumenta la incidencia del electromagnetismo, la mecánica cuántica y la nanotecnología en las necesidades de la sociedad contemporánea. (Ref.I.CN. F.5.19.2.). (I.2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.13', 'Explicar que en el modelo estándar todas las partículas y fuerzas se describen por medio de campos (de la partícula o fuerza) cuantizados y que sus —cuantos— no tienen masa, y relacionar la obtención de la masa con el campo de Higgs', 'BGU', 'I.CN.F.5.21.1. Argumenta mediante el modelo estándar, que los protones y neutrones no son partículas elementales, analizando las características ( masa, carga, espín) de las partículas elementales del átomo, distinguiendo partículas reales: leptones (electrón, neutrino del electrón, muon, neutrino del muon, tau y neutrino del tau), quarks (up, down, charm, strange, bottom y top), hadrones (bariones formados por tres quarks, mesones formados por pares quark-antiquark) y el efecto de las cuatro fuerzas fundamentales (electromagnética, nuclear fuerte y débil), mediante partículas virtuales o “cuantos del campo de fuerza” (gravitones, fotones, gluones y bosones) distinguiendo en estos últimos al bosón de Higgs. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.14', 'Discutir sobre el modelo estándar y reconocer que explica todo lo que se observa hasta ahora en el universo, excluyendo a la gravedad, la materia oscura y la energía oscura', 'BGU', 'Argumenta el modelo estándar “Lambda-CDM” como una explicación a todo lo observado en el universo, a excepción de la gravedad, materia, energía oscura, las características y los efectos de estas últimas. (Ref. I.CN.F.5.22.1.) (I.2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.4', 'Indagar sobre el principio de incertidumbre de Heisenberg, en función de reconocer que para las llamadas partículas cuánticas existe una incertidumbre al tratar de determinar su posición y velocidad (momento lineal) simultáneamente. CN', 'BGU', 'Explica los fenómenos de radiación del cuerpo negro, efecto fotoeléctrico, la radiación electromagnética (considerando la luz como partículas), el principio de incertidumbre de Heisenberg. (Ref.I.CN. F.5.19.1.) (I.2) Argumenta la incidencia del electromagnetismo, la mecánica cuántica y la nanotecnología en las necesidades de la sociedad contemporánea. (Ref.I.CN. F.5.19.2.). (I.2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.7', 'Distinguir que la radiactividad es el fenómeno por el cual el átomo radiactivo emite ciertas —radiaciones— y este se transforma en otro elemento químico (el objetivo de los alquimistas), y establecer que hay tres formas comunes de desintegración radiactiva (alfa, beta y gamma) debido a la acción de la fuerza nuclear débil, para analizar los efectos de la emisión de cada una. CN', 'BGU', 'I.CN.F.5.20.1. Fundamenta las cuatro fuerzas de la naturaleza: electromagnética, nuclear fuerte, nuclear débil, (estableciendo que hay tres formas comunes de desintegración radiactiva: alfa, beta y gamma) y gravitacional, valorando los efectos que tiene la tecnología en la revolución industrial. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.8', 'Explicar mediante la indagación científica la importancia de las fuerzas fundamentales de la naturaleza (nuclear fuerte, nuclear débil, electromagnética y gravitacional), en los fenómenos naturales la vida cotidiana', 'BGU', 'I.CN.F.5.20.1. Fundamenta las cuatro fuerzas de la naturaleza: electromagnética, nuclear fuerte, nuclear débil, (estableciendo que hay tres formas comunes de desintegración radiactiva: alfa, beta y gamma) y gravitacional, valorando los efectos que tiene la tecnología en la revolución industrial. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.5.9', 'Determinar que los quarks son partículas elementales del átomo que constituyen a los protones, neutrones y cientos de otras partículas subnucleares (llamadas colectivamente hadrones), en función de sus características. CN', 'BGU', 'I.CN.F.5.21.1. Argumenta mediante el modelo estándar, que los protones y neutrones no son partículas elementales, analizando las características ( masa, carga, espín) de las partículas elementales del átomo, distinguiendo partículas reales: leptones (electrón, neutrino del electrón, muon, neutrino del muon, tau y neutrino del tau), quarks (up, down, charm, strange, bottom y top), hadrones (bariones formados por tres quarks, mesones formados por pares quark-antiquark) y el efecto de las cuatro fuerzas fundamentales (electromagnética, nuclear fuerte y débil), mediante partículas virtuales o “cuantos del campo de fuerza” (gravitones, fotones, gluones y bosones) distinguiendo en estos últimos al bosón de Higgs. (I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.6.2', 'Ejemplificar dentro de las actividades humanas, los avances de la mecatrónica al servicio de la sociedad, que han facilitado las labores humanas con la finalidad de proponer alguna creación propia', 'BGU', 'I.CN.F.5.16.1. Explica los campos eléctricos generados en las proximidades de flujos magnéticos variables, los campos eléctricos generados en las proximidades de flujos eléctricos variables, el mecanismo de la radiación electromagnética por medio de la observación de videos (mostrando el funcionamiento de aparatos de uso cotidiano), ejemplificando los avances de la mecatrónica al servicio de la sociedad. (I.1., I.2.)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.6.4', 'Analizar la incidencia del electromagnetismo, la mecánica cuántica y la nanotecnología en las necesidades de la sociedad contemporánea', 'BGU', 'Explica los fenómenos de radiación del cuerpo negro, efecto fotoeléctrico, la radiación electromagnética (considerando la luz como partículas), el principio de incertidumbre de Heisenberg. (Ref.I.CN. F.5.19.1.) (I.2) Argumenta la incidencia del electromagnetismo, la mecánica cuántica y la nanotecnología en las necesidades de la sociedad contemporánea. (Ref.I.CN. F.5.19.2.). (I.2)'),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.6.5', 'Analizar los efectos que tiene la tecnología en la revolución de las industrias, con el fin de concienciar que el uso indebido del conocimiento y en especial que la aplicación de leyes físicas genera perjuicios a la sociedad. CN', 'BGU', null),
  ((select id from asignaturas where codigo = 'FIS'), 'F.5.6.6', 'Analizar y relacionar las cuatro fuerzas fundamentales de la naturaleza (fuerza electromagnética, fuerza nuclear fuerte, fuerza nuclear débil y fuerza gravitacional) con los desafíos tecnológicos y científicos durante la Revolución Industrial, demostrando resiliencia al identificar cómo el conocimiento y la aplicación de estas fuerzas permitieron superar obstáculos y transformar la sociedad', 'BGU', null),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.1', 'Contrastar los conceptos de historia e historiografía con el fin de diferenciar la realidad de la construcción intelectual. CS', 'BGU', 'I.CS.H.5.1.1. Contrasta los conceptos de historia e historiografía, mediante el uso técnico y ético de diversas fuentes, relativizando los diversos enfoques, con el fin de diferenciarla realidad de la construcción intelectual. (J.2., J.3., I.2.) I.CS.H.5.1.2. Examina el término “cultura” como producción material y simbólica, empleando y relativizando fuentes y enfoques. (J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.10', 'Identificar las materias primas y explicar su relación con el tipo de utensilios y herramientas que se confeccionaban. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.11', 'Determinar el impacto de la revolución neolítica (domesticación de plantas y animales y sedentarismo) en la transformación de la sociedad humana. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.14', 'Analizar y evaluar el rol y prestigio de la mujer en la comunidad primitiva a partir de su función productiva, social y cultural. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.15', 'Determinar las causas de la crisis de la comunidad matriarcal y la irrupción del dominio patriarcal en el desarrollo de la humanidad (machismo). CS', 'BGU', 'I.CS.H.5.3.1. Explica las circunstancias que marcaron la transición de la comunidad primitiva a la sociedad dividida en clases y la existencia de castas, evaluando el papel de la educación y la división de trabajo en ella. (J.1., J.3.) I.CS.H.5.3.2. Analiza las causas y circunstancias que originaron la crisis de la comunidad matriarcal, la propiedad privada sobre los medios de producción y la transformación de la concepción del ser humano como cosa o mercancía. (J.1., J.3.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.16', 'Describir y valorar los grandes aportes de las culturas de Mesopotamia al desarrollo tecnológico, económico y científico desde la perspectiva de su condición de “cuna de la humanidad”. CS', 'BGU', 'I.CS.H.5.5.1. Describe los aportes tecnológicos, económicos y científicos de las culturas de Mesopotamia, Egipto, China y la India y su impacto en el mundo contemporáneo. (J.1., J.4., I.1.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.17', 'Describir y valorar los grandes aportes de la cultura china al desarrollo tecnológico, económico y científico de la humanidad. CS', 'BGU', 'I.CS.H.5.5.1. Describe los aportes tecnológicos, económicos y científicos de las culturas de Mesopotamia, Egipto, China y la India y su impacto en el mundo contemporáneo. (J.1., J.4., I.1.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.18', 'Describir y valorar los grandes aportes de la cultura de la India al desarrollo tecnológico, económico y científico. CS', 'BGU', 'I.CS.H.5.5.1. Describe los aportes tecnológicos, económicos y científicos de las culturas de Mesopotamia, Egipto, China y la India y su impacto en el mundo contemporáneo. (J.1., J.4., I.1.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.2', 'Examinar el término “cultura” como producción material y simbólica y ejemplificar con aspectos de la vida cotidiana. CS', 'BGU', 'I.CS.H.5.1.1. Contrasta los conceptos de historia e historiografía, mediante el uso técnico y ético de diversas fuentes, relativizando los diversos enfoques, con el fin de diferenciarla realidad de la construcción intelectual. (J.2., J.3., I.2.) I.CS.H.5.1.2. Examina el término “cultura” como producción material y simbólica, empleando y relativizando fuentes y enfoques. (J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.20', 'Describir y valorar los grandes aportes de la cultura egipcia al desarrollo tecnológico, económico y científico', 'BGU', 'I.CS.H.5.5.1. Describe los aportes tecnológicos, económicos y científicos de las culturas de Mesopotamia, Egipto, China y la India y su impacto en el mundo contemporáneo. (J.1., J.4., I.1.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.22', 'Investigar y valorar el rol de la mujer en la sociedad del Medio Oriente en comparación con la situación contemporánea. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.23', 'Analizar y discutir el concepto de “yihad” en la cultura islámica a la luz del análisis de diversas fuentes', 'BGU', 'I.CS.H.5.8.1. Discute el concepto de “yihad” en la cultura islámica, en función de comprender los antecedentes históricos del conflicto judío-palestino. (I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.24', 'Reconocer la influencia de los griegos, sobre todo en el Imperio romano, en el Imperio bizantino y, casi dos mil años después, en la Europa del Renacimiento. CS', 'BGU', 'I.CS.H.5.6.1. Distingue el alcance e influencia de la civilización griega en los imperios romano y bizantino, en la Europa del Renacimiento y en la cultura occidental; así como las limitaciones de la democracia y la ciudadanía y su relación con los postulados básicos del derecho romano y derecho anglosajón. (J.1., I.2.) I.CS.H.5.6.2. Analiza los problemas de la expansión imperial romana, las causas de su decadencia y caída, sus diferencias en cuanto al arte y la cultura entre el Imperio romano de Occidente y de Oriente, reconociendo las contribuciones del derecho romano al sistema jurídico. (J.1., I.2.) I.CS.H.5.6.3. Analiza las características principales del monoteísmo y la concepción lineal del tiempo; y el derecho romano y su relación con el sistema jurídico ecuatoriano. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.25', 'Valorar la influencia del pensamiento griego en la cultura occidental, mediante el reconocimiento del carácterracional que lo distinguió. CS', 'BGU', 'I.CS.H.5.6.1. Distingue el alcance e influencia de la civilización griega en los imperios romano y bizantino, en la Europa del Renacimiento y en la cultura occidental; así como las limitaciones de la democracia y la ciudadanía y su relación con los postulados básicos del derecho romano y derecho anglosajón. (J.1., I.2.) I.CS.H.5.6.2. Analiza los problemas de la expansión imperial romana, las causas de su decadencia y caída, sus diferencias en cuanto al arte y la cultura entre el Imperio romano de Occidente y de Oriente, reconociendo las contribuciones del derecho romano al sistema jurídico. (J.1., I.2.) I.CS.H.5.6.3. Analiza las características principales del monoteísmo y la concepción lineal del tiempo; y el derecho romano y su relación con el sistema jurídico ecuatoriano. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.26', 'Distinguir y explicar las limitaciones de la democracia y de la ciudadanía en la civilización griega. CS', 'BGU', 'I.CS.H.5.6.1. Distingue el alcance e influencia de la civilización griega en los imperios romano y bizantino, en la Europa del Renacimiento y en la cultura occidental; así como las limitaciones de la democracia y la ciudadanía y su relación con los postulados básicos del derecho romano y derecho anglosajón. (J.1., I.2.) I.CS.H.5.6.2. Analiza los problemas de la expansión imperial romana, las causas de su decadencia y caída, sus diferencias en cuanto al arte y la cultura entre el Imperio romano de Occidente y de Oriente, reconociendo las contribuciones del derecho romano al sistema jurídico. (J.1., I.2.) I.CS.H.5.6.3. Analiza las características principales del monoteísmo y la concepción lineal del tiempo; y el derecho romano y su relación con el sistema jurídico ecuatoriano. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.27', 'Investigar y valorar los aportes de la mujer griega desde diversos ámbitos de participación: Safo de Lesbos, Aspasia de Mileto e Hipatia. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.29', 'Comprender las causas y los principales problemas de la expansión imperial romana. CS', 'BGU', 'I.CS.H.5.6.1. Distingue el alcance e influencia de la civilización griega en los imperios romano y bizantino, en la Europa del Renacimiento y en la cultura occidental; así como las limitaciones de la democracia y la ciudadanía y su relación con los postulados básicos del derecho romano y derecho anglosajón. (J.1., I.2.) I.CS.H.5.6.2. Analiza los problemas de la expansión imperial romana, las causas de su decadencia y caída, sus diferencias en cuanto al arte y la cultura entre el Imperio romano de Occidente y de Oriente, reconociendo las contribuciones del derecho romano al sistema jurídico. (J.1., I.2.) I.CS.H.5.6.3. Analiza las características principales del monoteísmo y la concepción lineal del tiempo; y el derecho romano y su relación con el sistema jurídico ecuatoriano. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.3', 'Explicar y valorar la importancia del trabajo colectivo y solidario como condición de la existencia y supervivencia humana. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.31', 'Analizar y comparar los roles de la mujer de los diferentes estratos sociales en la Roma antigua. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.32', 'Determinar los elementos del judaísmo que influyeron en la conformación de la cultura occidental mediante un análisis del monoteísmo y la concepción lineal del tiempo', 'BGU', 'I.CS.H.5.6.1. Distingue el alcance e influencia de la civilización griega en los imperios romano y bizantino, en la Europa del Renacimiento y en la cultura occidental; así como las limitaciones de la democracia y la ciudadanía y su relación con los postulados básicos del derecho romano y derecho anglosajón. (J.1., I.2.) I.CS.H.5.6.2. Analiza los problemas de la expansión imperial romana, las causas de su decadencia y caída, sus diferencias en cuanto al arte y la cultura entre el Imperio romano de Occidente y de Oriente, reconociendo las contribuciones del derecho romano al sistema jurídico. (J.1., I.2.) I.CS.H.5.6.3. Analiza las características principales del monoteísmo y la concepción lineal del tiempo; y el derecho romano y su relación con el sistema jurídico ecuatoriano. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.6', 'Aplicar técnica y éticamente las diversas fuentes en una investigación', 'BGU', 'I.CS.H.5.1.1. Contrasta los conceptos de historia e historiografía, mediante el uso técnico y ético de diversas fuentes, relativizando los diversos enfoques, con el fin de diferenciarla realidad de la construcción intelectual. (J.2., J.3., I.2.) I.CS.H.5.1.2. Examina el término “cultura” como producción material y simbólica, empleando y relativizando fuentes y enfoques. (J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.7', 'Explicar y valorar la función del trabajo humano en la construcción de la historia y la cultura. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.8', 'Describir y evaluar la influencia de la elaboración de herramientas en la transformación biológica y social del ser humano. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.1.9', 'Relacionar e interpretar las características esenciales del Paleolítico y la producción del arte rupestre. CS', 'BGU', 'I.CS.H.5.2.1. Explica la importancia y función del trabajo colectivo y solidario, y la elaboración de herramientas como condición en la transformación biológica y social del ser humano y posterior revolución neolítica. (I.2.) I.CS.H.5.2.2. Compara las características esenciales del Paleolítico (modo de producción, relaciones sociales, materias primas y herramientas y la producción de arte rupestre) con la revolución neolítica. (I.2.) I.CS.H.5.2.3. Explica el impacto de la revolución neolítica en la transformación de la sociedad humana, destacando la domesticación de plantas y animales en la producción de excedentes, la división y especialización del trabajo. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.1', 'Determinar las causas y consecuencias de la decadencia y caída del Imperio romano. CS', 'BGU', null),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.10', 'Explicar el contexto en el que surgieron las primeras universidades europeas, y el papel que desempeñó la Iglesia en la trasmisión de la cultura. CS', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.12', 'Distinguir e interpretar las principales características del arte arquitectónico románico y gótico en función de su simbología social', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.13', 'Determinar y comprender el origen y los principios fundamentales del Islam. CS', 'BGU', 'I.CS.H.5.8.2. Analiza el origen, la expansión y los principios fundamentales del Islam y su relación en el conflicto entre judíos y palestinos. (I.2.) I.CS.H.5.8.3. Discute los principios comunes que comparten el islamismo, el cristianismo y el judaísmo, su relación con los posibles antecedentes históricos del conflicto entre judíos y palestinos y reconoce la influencia de la civilización árabe en el arte y la cultura. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.14', 'Describir y evaluar la influencia cultural del Islam en la península Ibérica durante la Edad Media y su traslado a América con la conquista española. CS', 'BGU', 'I.CS.H.5.8.2. Analiza el origen, la expansión y los principios fundamentales del Islam y su relación en el conflicto entre judíos y palestinos. (I.2.) I.CS.H.5.8.3. Discute los principios comunes que comparten el islamismo, el cristianismo y el judaísmo, su relación con los posibles antecedentes históricos del conflicto entre judíos y palestinos y reconoce la influencia de la civilización árabe en el arte y la cultura. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.15', 'Sintetizar la expansión del Islam entre los siglos VII y VIII desde la península Ibérica en occidente hasta la India en oriente. CS', 'BGU', 'I.CS.H.5.8.2. Analiza el origen, la expansión y los principios fundamentales del Islam y su relación en el conflicto entre judíos y palestinos. (I.2.) I.CS.H.5.8.3. Discute los principios comunes que comparten el islamismo, el cristianismo y el judaísmo, su relación con los posibles antecedentes históricos del conflicto entre judíos y palestinos y reconoce la influencia de la civilización árabe en el arte y la cultura. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.16', 'Describir y analizar las principales contribuciones de la civilización árabe al arte y la cultura. CS', 'BGU', 'I.CS.H.5.8.2. Analiza el origen, la expansión y los principios fundamentales del Islam y su relación en el conflicto entre judíos y palestinos. (I.2.) I.CS.H.5.8.3. Discute los principios comunes que comparten el islamismo, el cristianismo y el judaísmo, su relación con los posibles antecedentes históricos del conflicto entre judíos y palestinos y reconoce la influencia de la civilización árabe en el arte y la cultura. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.17', 'Investigar y contrastar en fuentes diversas la situación y el rol de la mujer dentro de las sociedades islámicas', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.18', 'Argumentar los esenciales principios comunes del judaísmo, el cristianismo y el islamismo y sus diferencias fundamentales', 'BGU', 'I.CS.H.5.8.2. Analiza el origen, la expansión y los principios fundamentales del Islam y su relación en el conflicto entre judíos y palestinos. (I.2.) I.CS.H.5.8.3. Discute los principios comunes que comparten el islamismo, el cristianismo y el judaísmo, su relación con los posibles antecedentes históricos del conflicto entre judíos y palestinos y reconoce la influencia de la civilización árabe en el arte y la cultura. (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.2', 'Caracterizar y diferenciar el Imperio romano de Occidente del Imperio romano de Oriente en el arte y la cultura', 'BGU', null),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.23', 'Reconocer la Ilustración como base intelectual de la modernidad, sus principales representantes y postulados. CS', 'BGU', 'I.CS.H.5.9.4. Analiza las causas y consecuencias de la Revolución francesa considerando el proyecto napoleónico y su vinculación con el humanismo renacentista y la Ilustración. (I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.25', 'Argumentar sobre las principales causas y consecuencias de la Revolución francesa y la vigencia de sus postulados principales hasta el presente. CS', 'BGU', 'I.CS.H.5.9.4. Analiza las causas y consecuencias de la Revolución francesa considerando el proyecto napoleónico y su vinculación con el humanismo renacentista y la Ilustración. (I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.26', 'Determinar los alcances y las limitaciones del proyecto napoleónico en función de la expansión de los principios de la Revolución francesa', 'BGU', 'I.CS.H.5.9.4. Analiza las causas y consecuencias de la Revolución francesa considerando el proyecto napoleónico y su vinculación con el humanismo renacentista y la Ilustración. (I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.27', 'Identificar y comprender el origen del movimiento obrero a partir de las revoluciones industriales y el surgimiento del pensamiento socialista. CS', 'BGU', 'I.CS.H.5.10.1. Examina el contexto de origen de los movimientos obreros, feministas, indígenas, ecologistas y ecofeministas a partir del estudio de sus reivindicaciones y propuestas frente al modelo capitalista de producción. (J.1., I.2., S.1.) I.CS.H.5.10.2. Examina el papel que cumplen los movimientos artísticos, las diversas expresiones de arte, los medios de comunicación impresos y audiovisuales en las relaciones de poder y conflictos sociales. (J.1., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.28', 'Identificar y contextualizar las reivindicaciones de los movimientos de mujeres e indígenas para comprender las razones de su invisibilización y exclusión milenaria. CS', 'BGU', 'I.CS.H.5.10.1. Examina el contexto de origen de los movimientos obreros, feministas, indígenas, ecologistas y ecofeministas a partir del estudio de sus reivindicaciones y propuestas frente al modelo capitalista de producción. (J.1., I.2., S.1.) I.CS.H.5.10.2. Examina el papel que cumplen los movimientos artísticos, las diversas expresiones de arte, los medios de comunicación impresos y audiovisuales en las relaciones de poder y conflictos sociales. (J.1., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.3', 'Analizar y valorar la importancia y trascendencia del Imperio bizantino en la cultura, la religión y la legislación a lo largo de la Edad Media. CS', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.30', 'Identificar y contextualizar las reivindicaciones de los movimientos ecologista y ecofeminista a partir de la crítica a la visión mercantilista de la Madre Tierra (Pachamama). CS', 'BGU', 'I.CS.H.5.10.1. Examina el contexto de origen de los movimientos obreros, feministas, indígenas, ecologistas y ecofeministas a partir del estudio de sus reivindicaciones y propuestas frente al modelo capitalista de producción. (J.1., I.2., S.1.) I.CS.H.5.10.2. Examina el papel que cumplen los movimientos artísticos, las diversas expresiones de arte, los medios de comunicación impresos y audiovisuales en las relaciones de poder y conflictos sociales. (J.1., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.31', 'Examinar y valorar las propuestas de los movimientos ecologistas frente al modelo capitalista de producción. CS', 'BGU', 'I.CS.H.5.10.1. Examina el contexto de origen de los movimientos obreros, feministas, indígenas, ecologistas y ecofeministas a partir del estudio de sus reivindicaciones y propuestas frente al modelo capitalista de producción. (J.1., I.2., S.1.) I.CS.H.5.10.2. Examina el papel que cumplen los movimientos artísticos, las diversas expresiones de arte, los medios de comunicación impresos y audiovisuales en las relaciones de poder y conflictos sociales. (J.1., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.33', 'Analizar y comprender el papel y la importancia de los medios de comunicación impresos y audiovisuales en la producción y la reproducción de las relaciones de poder', 'BGU', 'I.CS.H.5.10.1. Examina el contexto de origen de los movimientos obreros, feministas, indígenas, ecologistas y ecofeministas a partir del estudio de sus reivindicaciones y propuestas frente al modelo capitalista de producción. (J.1., I.2., S.1.) I.CS.H.5.10.2. Examina el papel que cumplen los movimientos artísticos, las diversas expresiones de arte, los medios de comunicación impresos y audiovisuales en las relaciones de poder y conflictos sociales. (J.1., J.3., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.4', 'Examinar y relacionar los procesos de expansión del cristianismo y del islamismo y los conflictos motivados por ellos. CS', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.6', 'Analizar y valorar el rol de la mujer desde la perspectiva del pensamiento judeocristiano. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.7', 'Reconocer las motivaciones económicas de las cruzadas en la Edad Media en el contexto de las luchas religiosas. CS', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.8', 'Analizar el papel e influencia del Tribunal de la Inquisición en la persecución de la ciencia y la caza de “brujas”. CS', 'BGU', 'I.CS.H.5.4.1. Analiza el rol y la influencia de la mujer en los diferentes tiempos y espacios, destacando su papel en la sociedad primitiva, sociedad del Medio Oriente, Roma y Grecia antigua y la Colonia, y su protagonismo en Atenas y Esparta. (J.4., I.2.) I.CS.H.5.4.2. Examina la diversidad de pensamiento en la concepción y protagonismo de la mujer, destacando el pensamiento judeocristiano, la cacería de “brujas”, y el rol de la mujer en la sociedad islámica, valorando el protagonismo sociopolítico de Dolores Cacuango, Tránsito Amaguaña y Rigoberta Menchú en los procesos de liberación de Ecuador y América Latina. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.2.9', 'Comprender el intento del Imperio carolingio de recuperar los ámbitos político, religioso y cultural de la época medieval considerando su legado a la conformación del Sacro Imperio Romano Germánico. CS', 'BGU', 'I.CS.H.5.7.1. Describe los procesos de expansión y cambios que trajeron consigo el islamismo y el cristianismo, y las motivaciones económicas de las cruzadas en la Edad Media. (I.2.) I.CS.H.5.7.2. Analiza la influencia del Imperio bizantino en la cultura, la religión y la legislación, y los principales aportes culturales del medioevo. (J.2., I.2.) I.CS.H.5.7.3. Examina el papel de la Iglesia en la formación de las universidades y la difusión de la cultura y el arte (romántico y gótico) en el contexto del Imperio carolingio, destacando los aportes artísticos y culturales del medioevo (arquitectura, pintura y escultura). (J.1., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.3.1', 'Identificar y valorar las producciones intelectuales más significativas de las culturas aborígenes de América Latina precolombina (mayas, aztecas e incas). CS', 'BGU', 'I.CS.H.5.11.1. Analiza las producciones intelectuales más significativas de las culturas aborígenes, sus formas de vida y organización social, sus edificaciones arquitectónicas y la vinculación existente entre la arquitectura y astronomía. (I.2.) I.CS.H.5.11.2. Explica los principios de organización e intercambio social de los pobladores nativos y sus destrezas arquitectónicas incaicas, distinguiendo los diseños y funciones arquitectónicas de mayas, aztecas e incas. (J.4., I.2.) I.CS.H.5.11.3. Relaciona la organización y diversidad productiva de los pisos ecológicos con la distribución demográfica dispersa, destacando la creatividad de mayas, aztecas e incas. (I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.3.10', 'Examinar el impacto de la Conquista a través del estudio de la implementación de relaciones de explotación y sometimiento de la población aborigen. CS', 'BGU', 'I.CS.H.5.12.1. Evalúa el impacto de la conquista en los aspectos ecológicos, culturales y sociales como resultado de la inserción de la evangelización, las relaciones de explotación a personas a través de haciendas y plantaciones, distinguiendo las semejanzas y diferencias entre estas últimas. (I.2.) I.CS.H.5.12.2. Examina las configuraciones económicas en el tiempo de la Colonia, mediante el análisis del papel asignado a la mita y a las formas de extracción de riqueza (hacienda y a la plantación), destacando sus semejanzas y diferencias. (I.2., S.1.) I.CS.H.5.12.3. Relaciona los antecedentes históricos de la comunidad afrodescendiente de Esmeraldas y El Chota con el tráfico de personas esclavizadas en el tiempo de la Colonia, y los elementos culturales integrados como resultado de sus traslados, considerando los factores de producción en la hacienda y en la plantación. (J.4., I.2.)'),
  ((select id from asignaturas where codigo = 'HIS'), 'H.5.3.11', 'Analizar el impacto ecológico y el cambio en los hábitos culturales y sociales de la población indígena a partir de la introducción de especies animales y vegetales foráneas. CS', 'BGU', 'I.CS.H.5.12.1. Evalúa el impacto de la conquista en los aspectos ecológicos, culturales y sociales como resultado de la inserción de la evangelización, las relaciones de explotación a personas a través de haciendas y plantaciones, distinguiendo las semejanzas y diferencias entre estas últimas. (I.2.) I.CS.H.5.12.2. Examina las configuraciones económicas en el tiempo de la Colonia, mediante el análisis del papel asignado a la mita y a las formas de extracción de riqueza (hacienda y a la plantación), destacando sus semejanzas y diferencias. (I.2., S.1.) I.CS.H.5.12.3. Relaciona los antecedentes históricos de la comunidad afrodescendiente de Esmeraldas y El Chota con el tráfico de personas esclavizadas en el tiempo de la Colonia, y los elementos culturales integrados como resultado de sus traslados, considerando los factores de producción en la hacienda y en la plantación. (J.4., I.2.)'),
