  ((select id from asignaturas where codigo = 'MAT'), 'M.3.1.24', 'Calcular raíces cuadradas y cúbicas utilizando la estimación, la descomposición en factores primos y la tecnología', 'Media', null),
  ((select id from asignaturas where codigo = 'MAT'), 'M.3.1.25', 'Leer y escribir cantidades expresadas en números romanos hasta 1 000', 'Media', 'I.M.3.4.1. Utiliza números romanos, decimales y fraccionarios para expresar y comunicar situaciones cotidianas, leer información de distintos medios y resolver problemas. (I.3.) I.M.3.4.2. Aplica las equivalencias entre números fraccionarios y decimales en la resolución de ejercicios y situaciones reales; decide según la naturaleza del cálculo y el procedimiento a utilizar. (I.1., I.3.)'),
  ((select id from asignaturas where codigo = 'MAT'), 'M.3.1.26', 'Reconocer, leer y escribir los números decimales utilizados en la vida cotidiana', 'Media', 'I.M.3.4.1. Utiliza números romanos, decimales y fraccionarios para expresar y comunicar situaciones cotidianas, leer información de distintos medios y resolver problemas. (I.3.) I.M.3.4.2. Aplica las equivalencias entre números fraccionarios y decimales en la resolución de ejercicios y situaciones reales; decide según la naturaleza del cálculo y el procedimiento a utilizar. (I.1., I.3.)'),
