  ((select id from asignaturas where codigo = 'CS'), 'CS.4.1.54', 'Discutir la pertinencia y validez de los postulados de Mahatma Gandhi en relación con la construcción de una cultura de paz y el respeto a los derechos humanos en la contemporaneidad', 'Superior', null),
